// ============================================================================
// ADMIN HONORIFICS — CRUD for honorifics management
// ============================================================================
// Actions: list, create, update, delete
// Used by: Admin dashboard for managing honorifics (Dr., Dra., Ing., etc.)
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import "@total-typescript/ts-reset";
import { z } from 'zod';
import postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

// ============================================================================
// TYPES & SCHEMAS
// ============================================================================

const ActionSchema = z.enum(['list', 'create', 'update', 'delete']);

const InputSchema = z.object({
  tenant_id: z.uuid(),
  action: ActionSchema,
  honorific_id: z.uuid().optional(),
  code: z.string().max(10).optional(),
  label: z.string().max(10).optional(),
  gender: z.enum(['M', 'F', 'N']).optional(),
  sort_order: z.number().int().min(0).max(999).optional(),
  is_active: z.boolean().optional(),
});

interface HonorificRow {
  readonly honorific_id: string;
  readonly code: string;
  readonly label: string;
  readonly gender: string | null;
  readonly sort_order: number;
  readonly is_active: boolean;
  readonly created_at: string;
}

type Result<T> = [Error | null, T | null];

// ============================================================================
// CRUD OPERATIONS
// ============================================================================

async function listHonorifics(tx: postgres.TransactionSql): Promise<Result<HonorificRow[]>> {
  const rows = await tx.values<[string, string, string, string | null, number, boolean, string][]>`
    SELECT honorific_id, code, label, gender, sort_order, is_active, created_at
    FROM honorifics
    ORDER BY sort_order ASC, label ASC
  `;
  const honorifics: HonorificRow[] = rows.map((row) => ({
    honorific_id: row[0],
    code: row[1],
    label: row[2],
    gender: row[3],
    sort_order: row[4],
    is_active: row[5],
    created_at: row[6],
  }));
  return [null, honorifics];
}

async function createHonorific(
  tx: postgres.TransactionSql,
  code: string,
  label: string,
  gender: string | null,
  sortOrder: number,
  isActive: boolean
): Promise<Result<HonorificRow>> {
  const rows = await tx.values<[string, string, string, string | null, number, boolean, string][]>`
    INSERT INTO honorifics (code, label, gender, sort_order, is_active)
    VALUES (${code}, ${label}, ${gender}, ${sortOrder}, ${isActive})
    RETURNING honorific_id, code, label, gender, sort_order, is_active, created_at
  `;
  const row = rows[0];
  if (row === undefined) return [new Error('create_failed: no row returned'), null];
  return [null, {
    honorific_id: row[0],
    code: row[1],
    label: row[2],
    gender: row[3],
    sort_order: row[4],
    is_active: row[5],
    created_at: row[6],
  }];
}

async function updateHonorific(
  tx: postgres.TransactionSql,
  id: string,
  code: string | null,
  label: string | null,
  gender: string | null,
  sortOrder: number | null,
  isActive: boolean | null
): Promise<Result<HonorificRow>> {
  const fields: string[] = [];
  const params: (string | number | boolean | null)[] = [];
  let paramIdx = 1;

  if (code != null) { fields.push(`code = $${String(paramIdx++)}`); params.push(code); }
  if (label != null) { fields.push(`label = $${String(paramIdx++)}`); params.push(label); }
  if (gender != null) { fields.push(`gender = $${String(paramIdx++)}`); params.push(gender); }
  if (sortOrder != null) { fields.push(`sort_order = $${String(paramIdx++)}`); params.push(sortOrder); }
  if (isActive != null) { fields.push(`is_active = $${String(paramIdx++)}`); params.push(isActive); }

  if (fields.length === 0) return [new Error('update_failed: no fields provided'), null];

  fields.push(`updated_at = NOW()`);
  params.push(id);

  const query = `UPDATE honorifics SET ${fields.join(', ')} WHERE honorific_id = $${String(paramIdx)}::uuid RETURNING honorific_id, code, label, gender, sort_order, is_active, created_at`;
  const rows = await tx.unsafe(query, params as readonly unknown[]).values();
  const row = rows[0];
  if (row === undefined) return [new Error(`update_failed: honorific '${id}' not found`), null];
  return [null, {
    honorific_id: row[0],
    code: row[1],
    label: row[2],
    gender: row[3],
    sort_order: row[4],
    is_active: row[5],
    created_at: row[6],
  }];
}

async function deleteHonorific(tx: postgres.TransactionSql, id: string): Promise<Result<{ readonly deleted: boolean }>> {
  await tx`DELETE FROM honorifics WHERE honorific_id = ${id}::uuid`;
  return [null, { deleted: true }];
}

// ============================================================================
// MAIN
// ============================================================================

export async function main(rawInput: unknown): Promise<Result<unknown>> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl == null || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  const effectiveTenantId = input.tenant_id || input.honorific_id || '00000000-0000-0000-0000-000000000000';

  if (input.action === 'list') {
    const [err, rows] = await withTenantContext(sql, effectiveTenantId, listHonorifics);
    if (err != null) return [err, null];
    const honorifics = rows ?? [];
    return [null, { honorifics, count: honorifics.length }];
  }

  if (input.action === 'create') {
    const code = input.code ?? '';
    const label = input.label ?? '';
    if (code === '' || label === '') {
      return [new Error('create_failed: code and label are required'), null];
    }
    const [err, row] = await withTenantContext(sql, effectiveTenantId, (tx) =>
      createHonorific(tx, code, label, input.gender ?? null, input.sort_order ?? 99, input.is_active ?? true)
    );
    if (err != null) return [err, null];
    return [null, row];
  }

  if (input.action === 'update') {
    const id = input.honorific_id;
    if (id == null) return [new Error('update_failed: honorific_id is required'), null];
    const [err, row] = await withTenantContext(sql, effectiveTenantId, (tx) =>
      updateHonorific(tx, id, input.code ?? null, input.label ?? null, input.gender ?? null, input.sort_order ?? null, input.is_active ?? null)
    );
    if (err != null) return [err, null];
    return [null, row];
  }

  if (input.action === 'delete') {
    const id = input.honorific_id;
    if (id == null) return [new Error('delete_failed: honorific_id is required'), null];
    const [err, result] = await withTenantContext(sql, effectiveTenantId, (tx) => deleteHonorific(tx, id));
    if (err != null) return [err, null];
    return [null, result];
  }

  return [new Error(`Unknown action: ${input.action}`), null];
}

// ============================================================================
// BOOKING RESCHEDULE — Cancel old booking + create new one atomically
// ============================================================================
// Reschedules a booking by running ALL 4 DB operations in a single
// sql.begin() transaction with RLS tenant context:
//   1. INSERT new booking
//   2. UPDATE old booking to 'rescheduled'
//   3. INSERT audit for old booking
//   4. INSERT audit for new booking
//
// Atomic: if ANY step fails, ALL steps rollback. No partial state.
// Go-style: no throw for control flow, no any, no as.
// Enforces state machine transitions via shared module.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import type { UUID } from '../internal/db-types';
import { toUUID } from '../internal/db-types';
import { withTenantContext } from '../internal/tenant-context';
import { validateTransition } from '../internal/state-machine';
import { createDbClient } from '../internal/db/client';

type Sql = postgres.Sql;

const InputSchema = z.object({
  booking_id: z.uuid(),
  new_start_time: z.coerce.date(),
  new_service_id: z.uuid().optional(),
  actor: z.enum(['client', 'provider', 'system']),
  actor_id: z.uuid().optional(),
  reason: z.string().max(500).optional(),
});

// ─── Output Types ───────────────────────────────────────────────────────────
export interface RescheduleResult {
  readonly old_booking_id: UUID;
  readonly new_booking_id: UUID;
  readonly old_status: string;
  readonly new_status: string;
  readonly old_start_time: string;
  readonly new_start_time: string;
  readonly new_end_time: string;
}

// ─── Typed Row Interfaces ───────────────────────────────────────────────────
interface OldBookingRow {
  readonly booking_id: string;
  readonly status: string;
  readonly client_id: string;
  readonly provider_id: string;
  readonly service_id: string;
  readonly start_time: string;
  readonly end_time: string;
  readonly idempotency_key: string;
}

interface ServiceRow {
  readonly service_id: string;
  readonly duration_minutes: number;
}

interface RescheduleWriteResult {
  readonly new_booking_id: string;
  readonly new_status: string;
  readonly new_start_time: string;
  readonly new_end_time: string;
  readonly old_booking_id: string;
  readonly old_status: string;
}

// Note: RESCHEDULABLE_STATUSES removed. State machine validation is now used.

// ─── Validation Functions ───────────────────────────────────────────────────
async function lookupService(
  sql: Sql,
  serviceId: string,
): Promise<[Error | null, ServiceRow | null]> {
  const rows = await sql.values`
    SELECT service_id, duration_minutes FROM services
    WHERE service_id = ${serviceId}::uuid AND is_active = true LIMIT 1
  `;
  const row = rows[0];
  if (row === undefined) {
    return [new Error(`Service ${serviceId} not found or inactive`), null];
  }
  return [null, { service_id: row[0], duration_minutes: row[1] }];
}

// ─── Main Entry Point ───────────────────────────────────────────────────────
export async function main(
  rawInput: unknown,
): Promise<[Error | null, RescheduleResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  try {
    // 1. Find old booking (admin read — booking_id as capability token)
    const bookingRows = await sql.values`
      SELECT booking_id, status, client_id, provider_id, service_id,
             start_time, end_time, idempotency_key
      FROM bookings
      WHERE booking_id = ${input.booking_id}::uuid
      LIMIT 1
    `;
    const bookingRow = bookingRows[0];
    if (bookingRow === undefined) {
      return [new Error(`Booking ${input.booking_id} not found`), null];
    }

    const oldBooking: OldBookingRow = {
      booking_id: bookingRow[0],
      status: bookingRow[1],
      client_id: bookingRow[2],
      provider_id: bookingRow[3],
      service_id: bookingRow[4],
      start_time: bookingRow[5],
      end_time: bookingRow[6],
      idempotency_key: bookingRow[7],
    };

    // 2. Validate state machine transition
    const [transitionErr] = validateTransition(oldBooking.status, 'rescheduled');
    if (transitionErr !== null) {
      return [transitionErr, null];
    }

    // 3. Validate actor permission
    if (input.actor === 'client' && oldBooking.client_id !== input.actor_id) {
      return [new Error('Unauthorized: client_id mismatch'), null];
    }
    if (input.actor === 'provider' && oldBooking.provider_id !== input.actor_id) {
      return [new Error('Unauthorized: provider_id mismatch'), null];
    }

    // 4. Lookup new service
    const serviceId = input.new_service_id ?? oldBooking.service_id;
    const [serviceErr, service] = await lookupService(sql, serviceId);
    if (serviceErr !== null || service === null) {
      return [serviceErr ?? new Error('Service not found'), null];
    }

    // 5-8. All writes inside tenant context transaction
    const newStartDateTime = input.new_start_time;
    const newEndTime = new Date(newStartDateTime.getTime() + service.duration_minutes * 60 * 1000);
    const newIdempotencyKey = `reschedule-${oldBooking.idempotency_key}-${String(Date.now())}`;

    const [txErr, writeResult] = await withTenantContext<RescheduleWriteResult>(
      sql,
      oldBooking.provider_id,
      async (tx) => {
        // 5. Check slot overlap (inside transaction — prevents race condition)
        const overlapRows = await tx.values`
          SELECT booking_id FROM bookings
          WHERE provider_id = ${oldBooking.provider_id}::uuid
            AND status NOT IN ('cancelled', 'no_show', 'rescheduled')
            AND booking_id != ${input.booking_id}::uuid
            AND start_time < ${newEndTime.toISOString()}::timestamptz
            AND end_time > ${newStartDateTime.toISOString()}::timestamptz
          LIMIT 1
        `;
        if (overlapRows[0] !== undefined) {
          return [new Error('New time slot is already booked'), null];
        }

        // 6. Create new booking
        const newRows = await tx.values`
          INSERT INTO bookings (
            client_id, provider_id, service_id,
            start_time, end_time, status, idempotency_key, rescheduled_from,
            gcal_sync_status, notification_sent
          ) VALUES (
            ${oldBooking.client_id}::uuid, ${oldBooking.provider_id}::uuid, ${serviceId}::uuid,
            ${newStartDateTime.toISOString()}::timestamptz, ${newEndTime.toISOString()}::timestamptz,
            'confirmed', ${newIdempotencyKey}, ${input.booking_id}::uuid,
            'pending', false
          )
          RETURNING booking_id, status, start_time, end_time
        `;
        const nbRow = newRows[0];
        if (nbRow === undefined) {
          return [new Error('Failed to create new booking'), null];
        }

        // 7. Update old booking to rescheduled
        const updRows = await tx.values`
          UPDATE bookings
          SET status = 'rescheduled', updated_at = NOW()
          WHERE booking_id = ${input.booking_id}::uuid
          RETURNING booking_id, status
        `;
        const uoRow = updRows[0];
        if (uoRow === undefined) {
          return [new Error('Failed to update old booking status'), null];
        }

        // 8. Audit for old booking
        await tx.unsafe(
          `INSERT INTO booking_audit (booking_id, from_status, to_status, changed_by, actor_id, reason, metadata)
           VALUES ($1::uuid, $2, 'rescheduled', $3, $4::uuid, $5, $6::jsonb)`,
          [
            input.booking_id,
            oldBooking.status,
            input.actor,
            input.actor_id ?? null,
            input.reason ?? 'Rescheduled to new time',
            JSON.stringify({ new_booking_id: nbRow[0] }),
          ],
        );

        // 9. Audit for new booking
        await tx.unsafe(
          `INSERT INTO booking_audit (booking_id, from_status, to_status, changed_by, actor_id, reason, metadata)
           VALUES ($1::uuid, null, 'confirmed', $2, $3::uuid, $4, $5::jsonb)`,
          [
            nbRow[0],
            input.actor,
            input.actor_id ?? null,
            'Created via reschedule',
            JSON.stringify({ old_booking_id: input.booking_id }),
          ],
        );

        const result: RescheduleWriteResult = {
          new_booking_id: nbRow[0],
          new_status: nbRow[1],
          new_start_time: nbRow[2],
          new_end_time: nbRow[3],
          old_booking_id: uoRow[0],
          old_status: uoRow[1],
        };

        return [null, result];
      },
    );

    if (txErr !== null || writeResult === null) {
      const msg = txErr?.message ?? 'Unknown transaction error';
      if (msg.includes('duplicate key') || msg.includes('unique constraint')) {
        return [new Error('Idempotency key conflict'), null];
      }
      if (msg.includes('booking_no_overlap') || msg.includes('exclusion constraint')) {
        return [new Error('This time slot was just booked. Please choose a different time.'), null];
      }
      return [txErr ?? new Error(msg), null];
    }

    const result: RescheduleResult = {
      old_booking_id: toUUID(writeResult.old_booking_id),
      new_booking_id: toUUID(writeResult.new_booking_id),
      old_status: writeResult.old_status,
      new_status: writeResult.new_status,
      old_start_time: oldBooking.start_time,
      new_start_time: writeResult.new_start_time,
      new_end_time: writeResult.new_end_time,
    };

    return [null, result];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    if (message.includes('duplicate key') || message.includes('unique constraint')) {
      return [new Error('Idempotency key conflict'), null];
    }
    if (message.includes('booking_no_overlap') || message.includes('exclusion constraint') || message.includes('overlaps')) {
      return [new Error('This time slot was just booked. Please choose a different time.'), null];
    }
    return [new Error(`Internal error: ${message}`), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// BOOKING SEARCH — Search and filter bookings
// ============================================================================
// Search by: date range, provider, client, status, service
// Pagination: offset + limit
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  provider_id: z.uuid().optional(),
  client_id: z.uuid().optional(),
  status: z.enum(['pending', 'confirmed', 'in_service', 'completed', 'cancelled', 'no_show', 'rescheduled']).optional(),
  date_from: z.string().regex(/^\d{4}-\d{2}-\d{2}$/).optional(),
  date_to: z.string().regex(/^\d{4}-\d{2}-\d{2}$/).optional(),
  service_id: z.uuid().optional(),
  offset: z.number().int().min(0).default(0),
  limit: z.number().int().min(1).max(100).default(20),
});

interface BookingSearchRow {
  readonly booking_id: string;
  readonly start_time: string;
  readonly end_time: string;
  readonly status: string;
  readonly idempotency_key: string;
  readonly gcal_sync_status: string;
  readonly notification_sent: boolean;
  readonly created_at: string;
  readonly provider_name: string;
  readonly client_name: string;
  readonly service_name: string;
}

interface BookingSearchResult {
  readonly bookings: readonly BookingSearchRow[];
  readonly total: number;
  readonly offset: number;
  readonly limit: number;
}

export async function main(rawInput: unknown): Promise<[Error | null, BookingSearchResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;
  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  try {
    // Build WHERE clauses dynamically based on provided filters
    const conditions: string[] = [];
    const params: postgres.ParameterOrJSON<never>[] = [];
    let paramIdx = 1;

    if (input.provider_id !== undefined) {
      conditions.push('b.provider_id = $' + String(paramIdx) + '::uuid');
      params.push(input.provider_id);
      paramIdx++;
    }
    if (input.client_id !== undefined) {
      conditions.push('b.client_id = $' + String(paramIdx) + '::uuid');
      params.push(input.client_id);
      paramIdx++;
    }
    if (input.status !== undefined) {
      conditions.push('b.status = $' + String(paramIdx));
      params.push(input.status);
      paramIdx++;
    }
    if (input.date_from !== undefined) {
      conditions.push('b.start_time >= $' + String(paramIdx) + '::date');
      params.push(input.date_from);
      paramIdx++;
    }
    if (input.date_to !== undefined) {
      conditions.push('b.start_time < ($' + String(paramIdx) + '::date + INTERVAL \'1 day\')');
      params.push(input.date_to);
      paramIdx++;
    }
    if (input.service_id !== undefined) {
      conditions.push('b.service_id = $' + String(paramIdx) + '::uuid');
      params.push(input.service_id);
      paramIdx++;
    }

    const whereClause = conditions.length > 0 ? 'WHERE ' + conditions.join(' AND ') : '';

    // Count total
    const countRows = await sql.values<[bigint | number][]>(
      'SELECT COUNT(*) as total FROM bookings b ' + whereClause,
      params
    );
    const countRow = countRows[0];
    const total = countRow !== undefined ? Number(countRow[0]) : 0;

    // Fetch bookings
    const bookingRows = await sql.values<[
      string, string, string, string, string, string, boolean, string,
      string, string, string,
    ][]>(
      'SELECT b.booking_id, b.start_time, b.end_time, b.status, b.idempotency_key,' +
      ' b.gcal_sync_status, b.notification_sent, b.created_at,' +
      ' p.name as provider_name, pt.name as client_name, s.name as service_name' +
      ' FROM bookings b' +
      ' JOIN providers p ON p.provider_id = b.provider_id' +
      ' JOIN clients pt ON pt.client_id = b.client_id' +
      ' JOIN services s ON s.service_id = b.service_id' +
      ' ' + whereClause +
      ' ORDER BY b.start_time DESC' +
      ' LIMIT $' + String(paramIdx) + ' OFFSET $' + String(paramIdx + 1),
      params.concat([input.limit, input.offset])
    );

    const bookings: BookingSearchRow[] = bookingRows.map((row) => ({
      booking_id: row[0],
      start_time: row[1],
      end_time: row[2],
      status: row[3],
      idempotency_key: row[4],
      gcal_sync_status: row[5],
      notification_sent: row[6],
      created_at: row[7],
      provider_name: row[8],
      client_name: row[9],
      service_name: row[10],
    }));

    const result: BookingSearchResult = {
      bookings,
      total,
      offset: input.offset,
      limit: input.limit,
    };

    return [null, result];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return [new Error('Internal error: ' + message), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// CONVERSATION LOGGER — Log messages to conversations table
// ============================================================================
// Called after every incoming/outgoing message to maintain conversation history.
// Channel: telegram, web, api
// Direction: incoming, outgoing
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import { z } from 'zod';
import type postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  client_id: z.uuid().optional(),
  channel: z.enum(['telegram', 'web', 'api']),
  direction: z.enum(['incoming', 'outgoing']),
  content: z.string().min(1).max(2000),
  intent: z.string().optional(),
  metadata: z.record(z.string(), z.string()).optional(),
});

export async function main(rawInput: unknown): Promise<[Error | null, { message_id: string } | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  const rawObj = typeof rawInput === 'object' && rawInput !== null ? rawInput : {};
  let tenantId = '00000000-0000-0000-0000-000000000000';
  const tenantKeys = ['provider_id', 'user_id', 'admin_user_id', 'client_id', 'client_user_id'] as const;
  for (const key of tenantKeys) {
    const val = (rawObj as Record<string, unknown>)[key];
    if (typeof val === 'string') {
      tenantId = val;
      break;
    }
  }

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      const rows = await tx.values`
        INSERT INTO conversations (client_id, channel, direction, content, intent, metadata)
        VALUES (
          ${input.client_id ?? null}::uuid,
          ${input.channel},
          ${input.direction},
          ${input.content},
          ${input.intent ?? null},
          ${JSON.stringify(input.metadata ?? {})}::jsonb
        )
        RETURNING message_id
      `;

      const row = rows[0];
      if (row === undefined) {
        return [new Error('Failed to log conversation'), null];
      }

      return [null, { message_id: row[0] }];
    });

    if (txErr !== null) return [txErr, null];
    if (txData === null) return [new Error('Conversation logging failed'), null];
    return [null, txData];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return [new Error('Internal error: ' + message), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// DISTRIBUTED LOCK — Advisory lock for race condition prevention
// ============================================================================
// Uses booking_locks table for application-level locks.
// Go-style: no throw, no any, no as. Tuple return.
// Usage: acquire() → do work → release()
// ============================================================================

import { z } from 'zod';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  action: z.enum(['acquire', 'release', 'check', 'cleanup']),
  lock_key: z.string().min(1),
  owner_token: z.string().min(1).optional(),
  provider_id: z.uuid().optional(),
  start_time: z.iso.datetime().optional(),
  ttl_seconds: z.number().int().min(1).max(3600).default(30),
});

interface LockInfo {
  readonly lock_id: number;
  readonly lock_key: string;
  readonly owner_token: string;
  readonly provider_id: string;
  readonly start_time: string;
  readonly acquired_at: string;
  readonly expires_at: string;
}

interface LockRow {
  readonly lock_id: number;
  readonly lock_key: string;
  readonly owner_token: string;
  readonly provider_id: string;
  readonly start_time: string;
  readonly acquired_at: string;
  readonly expires_at: string;
}

interface LockResult {
  readonly acquired?: boolean;
  readonly released?: boolean;
  readonly locked?: boolean;
  readonly cleaned?: number;
  readonly lock?: LockInfo;
  readonly reason?: string;
  readonly owner?: string;
  readonly expires_at?: string;
}

// ─── Main Entry Point ───────────────────────────────────────────────────────
export async function main(
  rawInput: unknown,
): Promise<[Error | null, LockResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  try {
    switch (input.action) {
      case 'acquire': {
        if (input.owner_token === undefined) {
          return [new Error('owner_token is required for acquire'), null];
        }
        if (input.provider_id === undefined) {
          return [new Error('provider_id is required for acquire'), null];
        }
        if (input.start_time === undefined) {
          return [new Error('start_time is required for acquire'), null];
        }

        const expiresAt = new Date(Date.now() + input.ttl_seconds * 1000);

        // Try to insert lock (unique constraint on lock_key prevents duplicates)
        const rows = await sql.values`
          INSERT INTO booking_locks (lock_key, owner_token, provider_id, start_time, expires_at)
          VALUES (${input.lock_key}, ${input.owner_token}, ${input.provider_id}::uuid, ${input.start_time}::timestamptz, ${expiresAt.toISOString()}::timestamptz)
          ON CONFLICT (lock_key) DO NOTHING
          RETURNING lock_id, lock_key, owner_token, provider_id, start_time, acquired_at, expires_at
        `;

        const row = rows[0];
        if (row === undefined) {
          // Check if existing lock is expired (steal it)
          const existingRows = await sql.values`
            SELECT lock_id, lock_key, owner_token, provider_id, start_time, acquired_at, expires_at
            FROM booking_locks
            WHERE lock_key = ${input.lock_key} AND expires_at < NOW()
            LIMIT 1
          `;
          const existing = existingRows[0];
          if (existing !== undefined) {
            // Lock is expired — update it
            const updatedRows = await sql.values`
              UPDATE booking_locks
              SET owner_token = ${input.owner_token},
                  expires_at = ${expiresAt.toISOString()}::timestamptz,
                  acquired_at = NOW()
              WHERE lock_key = ${input.lock_key} AND expires_at < NOW()
              RETURNING lock_id, lock_key, owner_token, provider_id, start_time, acquired_at, expires_at
            `;
            const updated = updatedRows[0];
            if (updated !== undefined) {
              const lockInfo: LockInfo = {
                lock_id: updated[0],
                lock_key: updated[1],
                owner_token: updated[2],
                provider_id: updated[3],
                start_time: updated[4],
                acquired_at: updated[5],
                expires_at: updated[6],
              };
              const result: LockResult = { acquired: true, lock: lockInfo };
              return [null, result];
            }
          }
          const result: LockResult = { acquired: false, reason: 'Lock already held' };
          return [null, result];
        }

        const lockInfo: LockInfo = {
          lock_id: row[0],
          lock_key: row[1],
          owner_token: row[2],
          provider_id: row[3],
          start_time: row[4],
          acquired_at: row[5],
          expires_at: row[6],
        };
        const result: LockResult = { acquired: true, lock: lockInfo };
        return [null, result];
      }

      case 'release': {
        if (input.owner_token === undefined) {
          return [new Error('owner_token is required for release'), null];
        }

        const rows = await sql`
          DELETE FROM booking_locks
          WHERE lock_key = ${input.lock_key} AND owner_token = ${input.owner_token}
          RETURNING lock_key
        `;
        const row = rows[0];
        if (row === undefined) {
          const result: LockResult = { released: false, reason: 'Lock not found or wrong owner' };
          return [null, result];
        }
        const result: LockResult = { released: true };
        return [null, result];
      }

      case 'check': {
        const rows = await sql.values`
          SELECT lock_id, lock_key, owner_token, provider_id, start_time, acquired_at, expires_at
          FROM booking_locks
          WHERE lock_key = ${input.lock_key} AND expires_at > NOW()
          LIMIT 1
        `;
        const row = rows[0];
        if (row === undefined) {
          const result: LockResult = { locked: false };
          return [null, result];
        }
        const result: LockResult = { locked: true, owner: row[2], expires_at: row[6] };
        return [null, result];
      }

      case 'cleanup': {
        const rows = await sql`
          DELETE FROM booking_locks WHERE expires_at < NOW() RETURNING lock_key
        `;
        const result: LockResult = { cleaned: rows.length };
        return [null, result];
      }
    }
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${message}`), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// DLQ PROCESSOR — Dead Letter Queue handler for failed bookings
// ============================================================================
// Reads booking_dlq table, retries failed bookings, and manages resolution.
// States: pending -> resolved | discarded
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import { z } from 'zod';
import type postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  action: z.enum(['list', 'retry', 'resolve', 'discard', 'status']),
  dlq_id: z.number().int().optional(),
  max_retries: z.number().int().min(1).max(20).default(10),
});

interface DLQEntry {
  readonly dlq_id: number;
  readonly booking_id: string | null;
  readonly provider_id: string | null;
  readonly service_id: string | null;
  readonly failure_reason: string;
  readonly last_error_message: string;
  readonly last_error_stack: string | null;
  readonly original_payload: Readonly<Record<string, unknown>>;
  readonly idempotency_key: string;
  readonly status: 'pending' | 'resolved' | 'discarded';
  readonly created_at: string;
  readonly updated_at: string;
  readonly resolved_at: string | null;
  readonly resolved_by: string | null;
  readonly resolution_notes: string | null;
}

interface DLQRow {
  readonly dlq_id: number;
  readonly booking_id: string | null;
  readonly provider_id: string | null;
  readonly service_id: string | null;
  readonly failure_reason: string;
  readonly last_error_message: string;
  readonly last_error_stack: string | null;
  readonly original_payload: Readonly<Record<string, unknown>> | null;
  readonly idempotency_key: string;
  readonly status: string;
  readonly created_at: string;
  readonly updated_at: string;
  readonly resolved_at: string | null;
  readonly resolved_by: string | null;
  readonly resolution_notes: string | null;
}

function parseDLQRow(row: DLQRow): DLQEntry {
  return {
    dlq_id: row.dlq_id,
    booking_id: row.booking_id,
    provider_id: row.provider_id,
    service_id: row.service_id,
    failure_reason: row.failure_reason,
    last_error_message: row.last_error_message,
    last_error_stack: row.last_error_stack,
    original_payload: row.original_payload !== null ? row.original_payload : {},
    idempotency_key: row.idempotency_key,
    status: row.status as 'pending' | 'resolved' | 'discarded',
    created_at: row.created_at,
    updated_at: row.updated_at,
    resolved_at: row.resolved_at,
    resolved_by: row.resolved_by,
    resolution_notes: row.resolution_notes,
  };
}

interface DLQStatusRow {
  readonly status: string;
  readonly count: bigint | number;
}

interface DLQIdRow {
  readonly dlq_id: number;
}

interface DLQInput {
  readonly status_filter?: string | undefined;
  readonly resolution_notes?: string | undefined;
  readonly resolved_by?: string | undefined;
}

function parseRawInput(raw: unknown): DLQInput {
  if (typeof raw !== 'object' || raw === null) return {};
  const obj = raw as Record<string, unknown>;
  return {
    status_filter: typeof obj['status_filter'] === 'string' ? obj['status_filter'] : undefined,
    resolution_notes: typeof obj['resolution_notes'] === 'string' ? obj['resolution_notes'] : undefined,
    resolved_by: typeof obj['resolved_by'] === 'string' ? obj['resolved_by'] : undefined,
  };
}

export async function main(rawInput: unknown): Promise<[Error | null, Readonly<Record<string, unknown>> | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const { action, dlq_id } = parsed.data;
  const extraInput = parseRawInput(rawInput);

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  const rawObj = typeof rawInput === 'object' && rawInput !== null ? rawInput : {};
  let tenantId = '00000000-0000-0000-0000-000000000000';
  const tenantKeys = ['provider_id', 'user_id', 'admin_user_id', 'client_id', 'client_user_id'] as const;
  for (const key of tenantKeys) {
    const val = (rawObj as Record<string, unknown>)[key];
    if (typeof val === 'string') {
      tenantId = val;
      break;
    }
  }

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      switch (action) {
        case 'list': {
          const status = extraInput.status_filter !== undefined && ['pending', 'resolved', 'discarded'].includes(extraInput.status_filter) ? extraInput.status_filter : 'pending';
          const rows = await tx.values`
            SELECT dlq_id, booking_id, provider_id, service_id,
                   failure_reason, last_error_message, last_error_stack,
                   original_payload, idempotency_key, status,
                   created_at, updated_at, resolved_at, resolved_by, resolution_notes
            FROM booking_dlq
            WHERE status = ${status}
            ORDER BY created_at ASC
            LIMIT 100
          `;
          const entries: DLQEntry[] = rows.map((row) => parseDLQRow({
            dlq_id: row[0],
            booking_id: row[1],
            provider_id: row[2],
            service_id: row[3],
            failure_reason: row[4],
            last_error_message: row[5],
            last_error_stack: row[6],
            original_payload: row[7],
            idempotency_key: row[8],
            status: row[9],
            created_at: row[10],
            updated_at: row[11],
            resolved_at: row[12],
            resolved_by: row[13],
            resolution_notes: row[14],
          }));
          return [null, { entries, total: entries.length }];
        }

        case 'retry': {
          if (dlq_id === undefined) {
            const rowsRaw = await tx.values`
              SELECT dlq_id FROM booking_dlq
              WHERE status = 'pending'
              ORDER BY created_at ASC
              LIMIT 10
            `;
            const parsedRows = z.array(z.tuple([z.number()])).safeParse(rowsRaw);
            const rows = parsedRows.success ? parsedRows.data : [];
            const retried: number[] = [];
            for (const row of rows) {
              const id = row[0];
              await tx`
                UPDATE booking_dlq
                SET status = 'pending', updated_at = NOW()
                WHERE dlq_id = ${id}
              `;
              retried.push(id);
            }
            return [null, { retried, count: retried.length }];
          }

          const rows = await tx.values`
            SELECT dlq_id FROM booking_dlq
            WHERE dlq_id = ${dlq_id} AND status = 'pending'
            LIMIT 1
          `;
          const row = rows[0];
          if (row === undefined) {
            return [new Error('DLQ entry ' + String(dlq_id) + ' not found or not pending'), null];
          }

          await tx`
            UPDATE booking_dlq
            SET status = 'pending', updated_at = NOW()
            WHERE dlq_id = ${dlq_id}
          `;
          return [null, { retried: [dlq_id] }];
        }

        case 'resolve': {
          if (dlq_id === undefined) {
            return [new Error('dlq_id is required for resolve'), null];
          }

          await tx`
            UPDATE booking_dlq
            SET status = 'resolved',
                resolved_at = NOW(),
                resolved_by = ${extraInput.resolved_by ?? null},
                resolution_notes = ${extraInput.resolution_notes ?? null},
                updated_at = NOW()
            WHERE dlq_id = ${dlq_id}
          `;
          return [null, { resolved: dlq_id }];
        }

        case 'discard': {
          if (dlq_id === undefined) {
            return [new Error('dlq_id is required for discard'), null];
          }

          await tx`
            UPDATE booking_dlq
            SET status = 'discarded',
                resolved_at = NOW(),
                resolution_notes = ${extraInput.resolution_notes ?? 'Discarded manually'},
                updated_at = NOW()
            WHERE dlq_id = ${dlq_id}
          `;
          return [null, { discarded: dlq_id }];
        }

        case 'status': {
          const rows = await tx.values`
            SELECT status, COUNT(*) as count
            FROM booking_dlq
            GROUP BY status
          `;
          const stats: Record<string, number> = {};
          for (const row of rows) {
            stats[row[0]] = Number(row[1]);
          }
          return [null, stats];
        }

        default: {
          const _exhaustive: never = action;
          return [new Error(`Unknown action: ${String(_exhaustive)}`), null];
        }
      }
    });

    if (txErr !== null) return [txErr, null];
    if (txData === null) return [new Error('DLQ operation failed'), null];
    return [null, txData];
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${msg}`), null];
  } finally {
    await sql.end();
  }
}

/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : Sync booking to Google Calendar (provider + client)
 * DB Tables Used  : bookings, providers, clients, services
 * Concurrency Risk: NO — single booking read, no locks needed
 * GCal Calls      : YES — retryWithBackoff (3 attempts, 500ms*2^attempt)
 * Idempotency Key : N/A — read-only + update by booking_id
 * RLS Tenant ID   : YES — withTenantContext wraps DB ops
 * Zod Schemas     : YES — InputSchema validates all inputs
 */

// ============================================================================
// GCal SYNC — Sync booking to Google Calendar (provider + client)
// ============================================================================
// AGENTS.md §8 Anti-pattern fix: GCal API calls occur OUTSIDE DB transaction.
// Pattern: (1) SELECT booking in tx → (2) commit → (3) call GCal API →
//          (4) UPDATE booking in new tx
// Uses shared retryWithBackoff from internal/retry (DRY).
// Go-style: no throw, no any, no as. Tuple return.
// Retry: 3 attempts with exponential backoff [500ms, 1s, 2s]
// On failure: marks as 'pending' for reconciliation cron
// ============================================================================

import { z } from 'zod';
import type postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { buildGCalEvent } from '../internal/gcal_utils/buildGCalEvent';
import { retryWithBackoff } from '../internal/retry';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  booking_id: z.uuid(),
  action: z.enum(['create', 'update', 'delete']).default('create'),
  max_retries: z.number().int().min(1).max(5).default(3),
  tenant_id: z.uuid().optional(),
});

export interface GCalSyncResult {
  readonly booking_id: string;
  readonly provider_event_id: string | null;
  readonly client_event_id: string | null;
  readonly sync_status: 'synced' | 'partial' | 'pending';
  readonly retry_count: number;
  readonly errors: readonly string[];
}

interface BookingRow {
  readonly booking_id: string;
  readonly status: string;
  readonly start_time: string;
  readonly end_time: string;
  readonly gcal_provider_event_id: string | null;
  readonly gcal_client_event_id: string | null;
  readonly provider_name: string;
  readonly provider_calendar_id: string | null;
  readonly client_name: string;
  readonly client_calendar_id: string | null;
  readonly service_name: string;
}

function isGCalEventResponse(data: Readonly<Record<string, unknown>>): data is GCalEventResponse {
  return typeof data['id'] === 'string' && data['id'].length > 0;
}

function isRecord(data: unknown): data is Readonly<Record<string, unknown>> {
  return typeof data === 'object' && data !== null && !Array.isArray(data);
}

const GCAL_BASE = 'https://www.googleapis.com/calendar/v3';

interface GCalAPIResult {
  readonly ok: boolean;
  readonly data?: Readonly<Record<string, unknown>>;
  readonly error?: string;
}

interface GCalEventResponse {
  readonly id?: string;
}

async function callGCalAPI(
  method: string,
  path: string,
  calendarId: string,
  body?: object
): Promise<GCalAPIResult> {
  const accessToken = process.env['GCAL_ACCESS_TOKEN'];
  if (accessToken === undefined || accessToken === '') {
    return { ok: false, error: 'GCAL_ACCESS_TOKEN not configured' };
  }

  const url = `${GCAL_BASE}/calendars/${encodeURIComponent(calendarId)}/${path}`;

  try {
    const response = await fetch(url, {
      method,
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json',
      },
      body: body !== undefined ? JSON.stringify(body) : null,
      signal: AbortSignal.timeout(15000),
    });

    if (!response.ok) {
      const errorText = await response.text().catch(() => '');
      const isTransient = response.status >= 500 || response.status === 429;
      return {
        ok: false,
        error: `GCal API ${String(response.status)} (${isTransient ? 'transient' : 'permanent'}): ${errorText}`,
      };
    }

    const jsonData = await response.json();
    if (!isRecord(jsonData)) {
      return { ok: false, error: 'GCal API returned non-object response' };
    }
    return { ok: true, data: jsonData };
  } catch (e) {
    return { ok: false, error: `Network error: ${e instanceof Error ? e.message : String(e)}` };
  }
}

async function retryGCalOperation(
  operation: () => Promise<GCalAPIResult>,
  maxRetries: number,
  operationName: string,
): Promise<GCalAPIResult> {
  const result = await retryWithBackoff(operation, {
    maxAttempts: maxRetries,
    operationName,
  });

  if (result.success && result.data !== undefined && isRecord(result.data)) {
    return { ok: true, data: result.data };
  }

  const errorObj = result.error !== null ? result.error : new Error('Unknown error');
  return {
    ok: false,
    error: result.isPermanent
      ? `GCal API permanent error: ${errorObj.message}`
      : errorObj.message,
  };
}

// ─── Main Entry Point ───────────────────────────────────────────────────────
export async function main(
  rawInput: unknown,
): Promise<[Error | null, GCalSyncResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });
  const tenantId = input.tenant_id ?? '00000000-0000-0000-0000-000000000000';

  try {
    // STEP 1: Fetch booking details INSIDE transaction (short-lived)
    const [fetchErr, booking] = await withTenantContext(sql, tenantId, async (tx) => {
      const bookingRows = await tx.values<[
        string, string, string, string,
        string | null, string | null,
        string, string | null,
        string, string | null,
        string,
      ]>`
        SELECT b.booking_id, b.status, b.start_time, b.end_time,
               b.gcal_provider_event_id, b.gcal_client_event_id,
               p.name as provider_name, p.gcal_calendar_id as provider_calendar_id,
               pt.name as client_name, pt.gcal_calendar_id as client_calendar_id,
               s.name as service_name
        FROM bookings b
        JOIN providers p ON p.provider_id = b.provider_id
        JOIN clients pt ON pt.client_id = b.client_id
        JOIN services s ON s.service_id = b.service_id
        WHERE b.booking_id = ${input.booking_id}::uuid
        LIMIT 1
      `;

      const bookingRow = bookingRows[0];
      if (bookingRow === undefined) {
        return [new Error(`Booking ${input.booking_id} not found`), null];
      }

      const b: BookingRow = {
        booking_id: bookingRow[0],
        status: bookingRow[1],
        start_time: bookingRow[2],
        end_time: bookingRow[3],
        gcal_provider_event_id: bookingRow[4],
        gcal_client_event_id: bookingRow[5],
        provider_name: bookingRow[6],
        provider_calendar_id: bookingRow[7],
        client_name: bookingRow[8],
        client_calendar_id: bookingRow[9],
        service_name: bookingRow[10],
      };

      return [null, b];
    });

    if (fetchErr !== null) return [fetchErr, null];
    if (booking === null) return [new Error('Booking not found'), null];

    // STEP 2: GCal API calls OUTSIDE transaction (no DB lock held)
    const errors: string[] = [];
    let providerEventId: string | null = booking.gcal_provider_event_id;
    let clientEventId: string | null = booking.gcal_client_event_id;

    if (input.action === 'delete') {
      // Delete provider event
      if (booking.gcal_provider_event_id !== null && booking.provider_calendar_id !== null) {
        const calId = booking.provider_calendar_id;
        const eventId = booking.gcal_provider_event_id;
        const deleteResult = await retryGCalOperation(
          () => callGCalAPI('DELETE', `events/${eventId}`, calId),
          input.max_retries,
          'gcal_provider_delete',
        );
        if (!deleteResult.ok) {
          errors.push(`Provider event delete failed: ${deleteResult.error ?? 'Unknown error'}`);
        } else {
          providerEventId = null;
        }
      }

      // Delete client event
      if (booking.gcal_client_event_id !== null && booking.client_calendar_id !== null) {
        const calId = booking.client_calendar_id;
        const eventId = booking.gcal_client_event_id;
        const deleteResult = await retryGCalOperation(
          () => callGCalAPI('DELETE', `events/${eventId}`, calId),
          input.max_retries,
          'gcal_client_delete',
        );
        if (!deleteResult.ok) {
          errors.push(`Client event delete failed: ${deleteResult.error ?? 'Unknown error'}`);
        } else {
          clientEventId = null;
        }
      }
    } else {
      // Create/update provider event
      if (booking.provider_calendar_id !== null) {
        const calId = booking.provider_calendar_id;
        const eventBody = buildGCalEvent({
          booking_id: booking.booking_id,
          status: booking.status,
          start_time: booking.start_time,
          end_time: booking.end_time,
          provider_name: booking.provider_name,
          service_name: booking.service_name,
        });

        const providerResult = await retryGCalOperation(
          () => {
            if (booking.gcal_provider_event_id !== null) {
              return callGCalAPI('PUT', `events/${booking.gcal_provider_event_id}`, calId, eventBody);
            }
            return callGCalAPI('POST', 'events', calId, eventBody);
          },
          input.max_retries,
          'gcal_provider_sync',
        );

        if (providerResult.ok && providerResult.data !== undefined && isGCalEventResponse(providerResult.data)) {
          providerEventId = providerResult.data.id ?? null;
        } else {
          errors.push(`Provider event failed: ${providerResult.error ?? 'Unknown error'}`);
        }
      }

      // Create/update client event
      if (booking.client_calendar_id !== null) {
        const calId = booking.client_calendar_id;
        const eventBody = buildGCalEvent({
          booking_id: booking.booking_id,
          status: booking.status,
          start_time: booking.start_time,
          end_time: booking.end_time,
          provider_name: booking.provider_name,
          service_name: booking.service_name,
        });

        const clientResult = await retryGCalOperation(
          () => {
            if (booking.gcal_client_event_id !== null) {
              return callGCalAPI('PUT', `events/${booking.gcal_client_event_id}`, calId, eventBody);
            }
            return callGCalAPI('POST', 'events', calId, eventBody);
          },
          input.max_retries,
          'gcal_client_sync',
        );

        if (clientResult.ok && clientResult.data !== undefined && isGCalEventResponse(clientResult.data)) {
          clientEventId = clientResult.data.id ?? null;
        } else {
          errors.push(`Client event failed: ${clientResult.error ?? 'Unknown error'}`);
        }
      }
    }

    // STEP 3: Determine sync status
    let syncStatus: 'synced' | 'partial' | 'pending' = 'pending';
    if (errors.length === 0) {
      syncStatus = 'synced';
    } else if (providerEventId !== null || clientEventId !== null) {
      syncStatus = 'partial';
    }

    // STEP 4: Update booking with GCal event IDs (short-lived transaction)
    const [updateErr] = await withTenantContext(sql, tenantId, async (tx) => {
      await tx`
        UPDATE bookings
        SET gcal_provider_event_id = ${providerEventId},
            gcal_client_event_id = ${clientEventId},
            gcal_sync_status = ${syncStatus},
            gcal_last_sync = NOW(),
            gcal_retry_count = ${errors.length > 0 ? 1 : 0}
        WHERE booking_id = ${input.booking_id}::uuid
      `;
      return [null, true];
    });

    if (updateErr !== null) return [updateErr, null];

    const result: GCalSyncResult = {
      booking_id: input.booking_id,
      provider_event_id: providerEventId,
      client_event_id: clientEventId,
      sync_status: syncStatus,
      retry_count: 0,
      errors: errors,
    };

    return [null, result];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${message}`), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// GCal WEBHOOK RECEIVER — Process incoming Google Calendar push notifications
// ============================================================================
// Receives POST requests from Google Calendar push notification channels.
// On notification: fetches changed events, reconciles with DB bookings.
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import { z } from 'zod';
import type postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  headers: z.record(z.string(), z.string()).optional(),
  body: z.record(z.string(), z.unknown()).optional(),
  raw_channel_id: z.string().optional(),
});

const GCAL_BASE = 'https://www.googleapis.com/calendar/v3';

interface GCalEventItem {
  readonly id?: string;
  readonly status?: string;
  readonly description?: string;
  readonly summary?: string;
  readonly start?: { readonly dateTime?: string; readonly date?: string };
  readonly end?: { readonly dateTime?: string; readonly date?: string };
}

interface GCalEventsResponse {
  readonly items?: readonly GCalEventItem[];
  readonly nextSyncToken?: string;
  readonly nextPageToken?: string;
}

interface GCalFetchResult {
  readonly events: readonly GCalEventItem[];
  readonly nextSyncToken: string | null;
  readonly error: string | null;
}

interface WebhookResult {
  readonly acknowledged: boolean;
  readonly reason?: string;
  readonly changes_count?: number;
  readonly changes?: readonly { booking_id: string | null; event_id: string; status: string; action: string }[];
}

function isGCalEventsResponse(data: unknown): data is GCalEventsResponse {
  return typeof data === 'object' && data !== null && (
    'items' in (data as Record<string, unknown>) ||
    'nextSyncToken' in (data as Record<string, unknown>)
  );
}

async function fetchCalendarEvents(
  calendarId: string,
  accessToken: string,
  syncToken: string | null
): Promise<GCalFetchResult> {
  const url = GCAL_BASE + '/calendars/' + encodeURIComponent(calendarId) + '/events';
  const params: string[] = ['maxResults=50', 'showDeleted=true'];
  if (syncToken) params.push('syncToken=' + encodeURIComponent(syncToken));
  else params.push('timeMin=' + new Date(Date.now() - 86400000).toISOString());

  try {
    const response = await fetch(url + '?' + params.join('&'), {
      headers: { 'Authorization': 'Bearer ' + accessToken },
      signal: AbortSignal.timeout(15000),
    });

    if (!response.ok) {
      const text = await response.text().catch(function(): string { return ''; });
      if (response.status === 410 && syncToken) {
        return await fetchCalendarEvents(calendarId, accessToken, null);
      }
      return { events: [], nextSyncToken: null, error: 'GCal API ' + String(response.status) + ': ' + text };
    }

    const data = await response.json();
    if (!isGCalEventsResponse(data)) {
      return { events: [], nextSyncToken: null, error: 'Invalid GCal response format' };
    }
    const events = data.items ?? [];
    const nextSyncToken = typeof data.nextSyncToken === 'string' ? data.nextSyncToken : null;
    return { events, nextSyncToken, error: null };
  } catch (e) {
    return { events: [], nextSyncToken: null, error: e instanceof Error ? e.message : String(e) };
  }
}

export async function main(rawInput: unknown): Promise<[Error | null, WebhookResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;
  const dbUrl = process.env['DATABASE_URL'];
  const accessToken = process.env['GCAL_ACCESS_TOKEN'];
  if (dbUrl === undefined || dbUrl === '' || accessToken === undefined || accessToken === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL and GCAL_ACCESS_TOKEN required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  try {
    const headers = input.headers;
    const channelId = input.raw_channel_id ?? (headers !== undefined ? headers['X-Goog-Channel-Id'] : undefined);

    if (channelId === undefined) {
      return [new Error('Missing X-Goog-Channel-Id header'), null];
    }

    const tenantId = channelId || '00000000-0000-0000-0000-000000000000';

    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      const providerRows = await tx.values`
        SELECT provider_id, gcal_calendar_id FROM providers
        WHERE gcal_calendar_id IS NOT NULL
      `;

      let targetProvider: { provider_id: string; gcal_calendar_id: string | null } | null = null;
      for (const row of providerRows) {
        if (row[0] === channelId) {
          targetProvider = { provider_id: row[0], gcal_calendar_id: row[1] };
          break;
        }
      }

      if (targetProvider === null) {
        return [null, { acknowledged: true, reason: 'Unknown channel' }];
      }

      const calendarId = targetProvider.gcal_calendar_id;
      if (calendarId == null) {
        return [null, { acknowledged: true, reason: 'No calendar configured' }];
      }
      const result = await fetchCalendarEvents(calendarId, accessToken, null);
      if (result.error !== null) {
        return [new Error('GCal fetch error: ' + result.error), null];
      }

      const changes: { booking_id: string | null; event_id: string; status: string; action: string }[] = [];

      for (const event of result.events) {
        const eventId = typeof event.id === 'string' ? event.id : '';
        const status = typeof event.status === 'string' ? event.status : 'confirmed';
        const description = typeof event.description === 'string' ? event.description : '';

        const match = /ID de cita:\s*`?([0-9a-f-]+)`?/i.exec(description);
        const bookingId: string | null = match?.[1] ?? null;

        if (status === 'cancelled') {
          changes.push({ booking_id: bookingId, event_id: eventId, status, action: 'deleted' });
        } else if (bookingId !== null) {
          changes.push({ booking_id: bookingId, event_id: eventId, status, action: 'modified' });
        }
      }

      if (result.nextSyncToken !== null) {
        const configKey = 'gcal_sync_token_' + channelId;
        await tx`
          INSERT INTO system_config (config_key, config_value)
          VALUES (${configKey}, ${JSON.stringify({ token: result.nextSyncToken, updated_at: new Date().toISOString() })}::jsonb)
          ON CONFLICT (config_key) DO UPDATE SET config_value = EXCLUDED.config_value, updated_at = NOW()
        `;
      }

      const result: WebhookResult = { acknowledged: true, changes_count: changes.length, changes };
      return [null, result];
    });

    if (txErr !== null) return [txErr, null];
    if (txData === null) return [new Error('Webhook processing failed'), null];
    return [null, txData];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return [new Error('Internal error: ' + message), null];
  } finally {
    await sql.end();
  }
}

