function buildEmailContent(
  messageType: string,
  details: EmailDetails,
  actionLinks: readonly ActionLink[],
): EmailContent {
  const customSubject = typeof details.subject === 'string' ? details.subject : '';
  const customHtmlBody = typeof details.html_body === 'string' ? details.html_body : '';

  // Custom template passthrough
  if (messageType === 'custom') {
    return { subject: customSubject || 'Notificación del Sistema de Citas', html: customHtmlBody || '<p>Tienes una notificación.</p>' };
  }

  // Lookup template
  const tpl = EMAIL_TEMPLATES[messageType];
  if (tpl == null) {
    return { subject: 'Notificación del Sistema de Citas', html: `<p>Tienes una notificación: ${JSON.stringify(details)}</p>` };
  }

  const content = renderTemplate(tpl, details);
  const btnColor = (style: string) => style === 'danger' ? '#F44336' : style === 'secondary' ? '#757575' : '#4CAF50';
  const buttonsHtml = actionLinks.length > 0
    ? `<div style="margin: 30px 0;">${actionLinks.map(link => `<a href="${link.url}" style="display: inline-block; padding: 12px 24px; margin: 0 8px 8px 0; background-color: ${btnColor(link.style)}; color: white; text-decoration: none; border-radius: 4px; font-weight: bold;">${link.text}</a>`).join('')}</div>`
    : '';

  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; color: #333;">
  <div style="text-align: center; font-size: 48px; margin-bottom: 20px;">${tpl.icon}</div>
  ${content.html}
  ${buttonsHtml}
  <hr style="border: none; border-top: 1px solid #eee; margin: 30px 0;">
  <p style="color: #999; font-size: 12px;">Este es un mensaje automático del sistema de citas médicas. No respondas directamente a este correo.</p>
</body></html>`;

  return { subject: content.subject, html };
}

const InputSchema = z.object({
  to: z.email(),
  message_type: z.string().min(1),
  email_details: z.record(z.unknown()).optional(),
  action_links: z.array(z.object({
    text: z.string(),
    url: z.string().url(),
    style: z.enum(['primary', 'danger', 'secondary']).default('primary'),
  })).optional(),
});

interface GmailSendData {
  readonly sent: boolean;
  readonly message_id: string | null;
  readonly error: string | null;
}

export async function main(rawInput: unknown): Promise<Result<GmailSendData>> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) return [new Error('Validation error: ' + parsed.error.message), null];

  const { to, message_type, email_details, action_links } = parsed.data;

  const user = process.env['GMAIL_USER'];
  const pass = process.env['GMAIL_PASSWORD'];
  if (!user || !pass) return [new Error('GMAIL_USER and GMAIL_PASSWORD are required'), null];

  const transporter = nodemailer.createTransport({
    host: 'smtp.gmail.com',
    port: 587,
    secure: false,
    auth: { user, pass },
  });

  const content = buildEmailContent(message_type, email_details ?? {}, action_links ?? []);

  const maxRetries = 3;
  let lastError = 'Unknown';
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const info = await transporter.sendMail({ from: user, to, subject: content.subject, html: content.html });
      return [null, { sent: true, message_id: info.messageId ?? null, error: null }];
    } catch (err) {
      lastError = err instanceof Error ? err.message : String(err);
      if (err instanceof Error && err.message.includes('4')) {
        return [new Error(`Permanent error: ${err.message}`), null];
      }
    }
    if (attempt < maxRetries - 1) {
      const backoffMs = RETRY_BACKOFF_BASE_MS * Math.pow(RETRY_BACKOFF_MULTIPLIER, attempt);
      await new Promise(resolve => setTimeout(resolve, backoffMs));
    }
  }

  return [new Error(`Failed after ${String(maxRetries)} retries: ${lastError}`), null];
}

