// Type guard for intent validation
function isIntentType(value: string): value is IntentType {
  const values = Object.values(INTENT) as readonly string[];
  return values.includes(value);
}

// ============================================================================
// ENTITY EXTRACTION — Decomposed into single-resibility sub-functions
// ============================================================================

function extractDate(lowerText: string, text: string): string | null {
  for (const relDate of RELATIVE_DATES) {
    if (lowerText.includes(relDate)) return relDate;
  }
  const datePatterns: readonly RegExp[] = [
    /\b(\d{4}[-/]\d{1,2}[-/]\d{1,2})\b/,
    /\b(\d{1,2}[-/]\d{1,2}[-/]\d{2,4})\b/,
    /\b(\d{1,2}[-/]\d{1,2})\b/,
  ];
  for (const pattern of datePatterns) {
    const match = text.match(pattern);
    if (match?.[1] != null) return match[1];
  }
  for (const day of Object.keys(DAY_NAMES)) {
    if (lowerText.includes(day)) return day;
  }
  return null;
}

function extractTime(text: string): string | null {
  const patterns: readonly RegExp[] = [
    /(\d{1,2}:\d{2}\s*(am|pm|hrs|horas)?)/i,
    /(\d{1,2}\s*(am|pm|hrs|horas))/i,
    /las\s*(\d{1,2})\s*(am|pm|horas)?/i,
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match?.[1] != null) return match[1].trim();
  }
  return null;
}

function extractProviderName(text: string): string | null {
  const patterns: readonly RegExp[] = [
    /(?:dr|doctor|doctora)\.?\s+([A-Z][a-z]+)/i,
    /(?:con|para)\s+el\s+(?:dr|doctor)\.?\s+([A-Z][a-z]+)/i,
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match?.[1] != null) return `Dr. ${match[1]}`;
  }
  return null;
}

function extractProviderId(text: string): string | null {
  const patterns: readonly RegExp[] = [
    /proveedor\s+(\d+)/i,
    /provider\s+(\d+)/i,
    /doctor\s+(\d+)/i,
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match?.[1] != null) return match[1];
  }
  return null;
}

function extractServiceType(lowerText: string): string | null {
  for (const service of SERVICE_TYPES) {
    if (lowerText.includes(service)) return service;
  }
  return null;
}

function extractServiceId(text: string): string | null {
  const patterns: readonly RegExp[] = [
    /servicio\s+(\d+)/i,
    /service\s+(\d+)/i,
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match?.[1] != null) return match[1];
  }
  return null;
}

function extractBookingId(text: string): string | null {
  const patterns: readonly RegExp[] = [
    /\b([A-Z]{2,3}-\d{3,4})\b/,
    /#(\d{3,6})\b/,
    /reserva\s+(\d{3,6})\b/i,
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match?.[1] != null) return match[1];
  }
  return null;
}

function extractChannel(lowerText: string): string | null {
  if (lowerText.includes('telegram')) return 'telegram';
  if (lowerText.includes('email') || lowerText.includes('correo')) return 'email';
  if (lowerText.includes('sms') || lowerText.includes('mensaje')) return 'sms';
  return null;
}

function extractReminderWindow(lowerText: string): string | null {
  const patterns: readonly RegExp[] = [
    /(\d+min)\s*antes/i,
    /(\d+h)\s*antes/i,
    /(\d+)\s*minutos?\s*antes/i,
    /(\d+)\s*horas?\s*antes/i,
  ];
  for (const pattern of patterns) {
    const match = lowerText.match(pattern);
    if (match?.[1] != null) return match[1];
  }
  return null;
}

function extractEntities(text: string): EntityMap {
  const lowerText = text.toLowerCase();
  const provider_id = extractProviderId(text);
  if (provider_id != null) {
    return { date: extractDate(lowerText, text), time: extractTime(text),
      provider_name: extractProviderName(text), provider_id,
      service_type: extractServiceType(lowerText), service_id: null,
      booking_id: null, channel: null, reminder_window: null };
  }
  const service_id = extractServiceId(text);
  if (service_id != null) {
    return { date: extractDate(lowerText, text), time: extractTime(text),
      provider_name: extractProviderName(text), provider_id,
      service_type: extractServiceType(lowerText), service_id,
      booking_id: null, channel: null, reminder_window: null };
  }
  return {
    date: extractDate(lowerText, text), time: extractTime(text),
    provider_name: extractProviderName(text), provider_id,
    service_type: extractServiceType(lowerText), service_id,
    booking_id: extractBookingId(text),
    channel: extractChannel(lowerText),
    reminder_window: extractReminderWindow(lowerText),
  };
}

// ============================================================================
// CONTEXT DETECTION
// ============================================================================

function detectContext(text: string, entities: EntityMap): AvailabilityContext {
  const lower = text.toLowerCase();
  const is_today = lower.includes('hoy') || entities.date === 'hoy';
  const is_tomorrow = lower.includes('mañana') || lower.includes('manana') || entities.date === 'mañana';
  const is_urgent = URGENCY_WORDS.some(w => lower.includes(w));
  const is_flexible = FLEXIBILITY_KEYWORDS.some(w => lower.includes(w));

  let time_preference: AvailabilityContext['time_preference'] = 'any';
  if (lower.includes('por la mañana') || lower.includes('en la mañana')) time_preference = 'morning';
  else if (lower.includes('tarde') || lower.includes('por la tarde')) time_preference = 'afternoon';
  else if (lower.includes('noche')) time_preference = 'evening';

  let day_preference: string | null = null;
  for (const [day, fullName] of Object.entries(DAY_NAMES)) {
    if (lower.includes(day)) {
      day_preference = fullName;
      break;
    }
  }

  return {
    is_today,
    is_tomorrow,
    is_urgent,
    is_flexible,
    is_specific_date: entities.date != null,
    time_preference,
    day_preference,
  };
}

// ============================================================================
// RESPONSE STRATEGY
// ============================================================================

function suggestResponseType(intent: IntentType, context: AvailabilityContext, entities: EntityMap): string {
  if (intent === INTENT.URGENT_CARE) return 'urgent_options';
  if (intent === INTENT.RESCHEDULE) return 'reschedule_flow';
  if (intent === INTENT.CHECK_AVAILABILITY) {
    if (context.is_today) return 'no_availability_today';
    if (context.is_specific_date && context.day_preference != null) return 'filtered_search';
    if (context.is_specific_date) return 'availability_list';
    if (context.is_flexible) return 'general_search';
    return 'filtered_search';
  }
  if (intent === INTENT.CREATE_APPOINTMENT) {
    if (context.is_flexible) return 'general_search';
    if (entities.date == null || entities.time == null) return 'clarifying_question';
    return 'booking_confirmation';
  }
  if (intent === INTENT.ACTIVATE_REMINDERS) return 'activate_reminders_response';
  if (intent === INTENT.DEACTIVATE_REMINDERS) return 'deactivate_reminders_response';
  if (intent === INTENT.REMINDER_PREFERENCES) return 'reminder_preferences_response';
  if (intent === INTENT.GET_MY_BOOKINGS) return 'my_bookings_response';
  return 'standard_response';
}

