    followUpQuestion: null
  };
}

// ============================================================================
// INTENT DETECTION (Rules fallback)
// ============================================================================

function detectIntentRules(text: string): { readonly intent: IntentType; readonly confidence: number } {
  const lower = text.toLowerCase();

  // Urgency first — but only when it's MEDICAL urgency, not general context
  const medicalUrgencyPatterns = [
    'dolor', 'sangrando', 'no puedo esperar', 'urgente', 'emergencia', 'urgencia',
    'urjente', 'urgnete', 'urjencia', 'urgente',
    'nececito atencion', 'necesito atencion',
  ];
  const hasMedicalUrgency = medicalUrgencyPatterns.some(w => lower.includes(w));
  // Exclude non-medical contexts
  const hasNonMedicalContext = lower.includes('emergencia familiar') || lower.includes('emergencia laboral');
  if (hasMedicalUrgency && !hasNonMedicalContext) return { intent: INTENT.URGENT_CARE, confidence: 0.9 };

  // Reminder intents
  const activateKw = INTENT_KEYWORDS[INTENT.ACTIVATE_REMINDERS]?.keywords ?? [];
  const deactivateKw = INTENT_KEYWORDS[INTENT.DEACTIVATE_REMINDERS]?.keywords ?? [];
  const prefKw = INTENT_KEYWORDS[INTENT.REMINDER_PREFERENCES]?.keywords ?? [];
  if (deactivateKw.some(k => lower.includes(k))) return { intent: INTENT.DEACTIVATE_REMINDERS, confidence: 0.85 };
  if (activateKw.some(k => lower.includes(k))) return { intent: INTENT.ACTIVATE_REMINDERS, confidence: 0.85 };
  if (prefKw.some(k => lower.includes(k))) return { intent: INTENT.REMINDER_PREFERENCES, confidence: 0.85 };

  // Reschedule check
  const rescheduleKw = INTENT_KEYWORDS[INTENT.RESCHEDULE]?.keywords ?? [];
  const coreCreateKw = ['agendar', 'reservar', 'ajendar', 'sacar', 'pedir hora', 'necesito hora', 'consulta', 'visita', 'ver al doctor', 'konsulta', 'cosulta', 'resevar', 'truno', 'sita', 'agenda'];
  const hasRescheduleKeyword = rescheduleKw.some(k => lower.includes(k));
  const hasCreateKeyword = coreCreateKw.some(k => lower.includes(k));

  if (hasRescheduleKeyword && !hasCreateKeyword) return { intent: INTENT.RESCHEDULE, confidence: 0.8 };

  // Check availability
  const hasDayPref = Object.keys(DAY_NAMES).some(d => lower.includes(d));
  const hasRelDate = RELATIVE_DATES.some(r => lower.includes(r));
  if ((hasDayPref || hasRelDate) && lower.includes('hora')) return { intent: INTENT.CHECK_AVAILABILITY, confidence: 0.7 };

  // Cancel check
  const cancelKw = INTENT_KEYWORDS[INTENT.CANCEL_APPOINTMENT]?.keywords ?? [];
  if (cancelKw.some(k => lower.includes(k))) return { intent: INTENT.CANCEL_APPOINTMENT, confidence: 0.8 };

  for (const [intentKey, config] of Object.entries(INTENT_KEYWORDS)) {
    const typedIntent = intentKey as IntentType;
    if (typedIntent === INTENT.RESCHEDULE && hasCreateKeyword) continue;
    const keywords = config.keywords;
    const matchCount = keywords.filter((k: string) => lower.includes(k)).length;
    if (matchCount > 0) {
      const confidence = Math.min(0.33 * matchCount, 0.9);
      if (confidence >= CONFIDENCE_THRESHOLDS[typedIntent]) {
        return { intent: typedIntent, confidence };
      }
    }
  }

  return { intent: INTENT.UNKNOWN, confidence: 0.1 };
}

// ============================================================================
// INTENT PIPELINE — Hybrid LLM + Rules (extracted from main for SRP)
// ============================================================================

interface PipelineInput {
  readonly text: string;
  readonly chat_id: string;
  readonly provider_id?: string;
  readonly user_profile?: AIAgentInput['user_profile'];
}

interface PipelineOutput {
  readonly intent: IntentType;
  readonly confidence: number;
  readonly provider: string;
  readonly cot_reasoning: string;
  readonly result: IntentResult;
}

async function runIntentPipeline(
  input: PipelineInput,
  startMs: number,
): Promise<PipelineOutput> {
  const { text, chat_id, provider_id } = input;

  let intent: IntentType = INTENT.UNKNOWN;
  let confidence = 0.0;
  let provider = "fallback";
  let cot_reasoning = "Fallback to rules-based detection";

  const socialMatch = detectSocial(text);
  if (socialMatch != null) {
    intent = socialMatch.intent;
    confidence = socialMatch.confidence;
    provider = "fast-path";
    cot_reasoning = "Social fast-path matched";
  } else {
    const tfidfResult = classifyIntent(text);
    const hasEnoughContent = text.trim().split(/\s+/).length >= 2;
    if (tfidfResult.confidence >= 0.4 && hasEnoughContent) {
      const tfidfIntent = tfidfResult.intent as IntentType;
      if (isIntentType(tfidfIntent)) {
        intent = tfidfIntent;
        confidence = Math.max(tfidfResult.confidence, 0.5);
        provider = "fallback";
        cot_reasoning = `TF-IDF semantic match (${tfidfResult.scores[0]?.intent ?? 'unknown'})`;
      }
    }

    const skipLLM = (() => {
      try { if (typeof process !== 'undefined' && process.env['AI_AGENT_LLM_MODE'] === 'test') return true; } catch { /* ignore */ }
      return false;
    })();

    if (!skipLLM) {
      let ragContext: string | undefined;
      if (intent === INTENT.GENERAL_QUESTION || intent === INTENT.UNKNOWN) {
        const ragResult = await buildRAGContext(text, provider_id ?? null, 3);
        ragContext = ragResult.context;
        if (ragResult.count > 0) {
          const scope = ragResult.hasProviderSpecific ? 'provider-specific + public' : 'public only';
          cot_reasoning = `RAG: ${String(ragResult.count)} FAQs found (${scope})`;
        }
      }

      const systemPrompt = buildSystemPrompt(ragContext);
      const userMsg = buildUserMessage(text);
      const [llmErr, llmRes] = await runLLMInquiryWithPrompt(systemPrompt, userMsg);
      if (llmErr == null && llmRes != null) {
        intent = llmRes.intent;
        confidence = llmRes.confidence;
        provider = llmRes.provider;
        cot_reasoning = llmRes.cot_reasoning;
      } else {
        if (llmErr != null) console.log('[LLM ERROR]', llmErr.message);
        const rules = detectIntentRules(text);
        intent = rules.intent;
        confidence = rules.confidence;
      }
    } else {
      const rules = detectIntentRules(text);
      intent = rules.intent;
      confidence = rules.confidence;
    }
  }

  const entities = extractEntities(text);
  const context = detectContext(text, entities);
  const suggested_response_type = suggestResponseType(intent, context, entities);

  const { aiResponse, needsMoreInfo, followUpQuestion } = generateAIResponse(
    intent, entities, context, suggested_response_type, input.user_profile
  );

  const result: IntentResult = {
    intent, confidence, entities, context, suggested_response_type,
    ai_response: aiResponse, needs_more_info: needsMoreInfo,
    follow_up_question: followUpQuestion, cot_reasoning,
    validation_passed: true, validation_errors: [],
  };

  const verifiedResult = verifyUrgency(result, text);

  trace({
    chat_id, intent: verifiedResult.intent as IntentType,
    confidence: verifiedResult.confidence, provider,
    latency_ms: Date.now() - startMs,
    fallback_used: provider === "fallback",
    timestamp: new Date().toISOString(),
  });

  return { intent: verifiedResult.intent, confidence: verifiedResult.confidence, provider, cot_reasoning, result: verifiedResult };
}

export async function main(rawInput: unknown): Promise<{ readonly success: boolean; readonly data: IntentResult | null; readonly error_message: string | null; readonly error_code?: string }> {
  const startMs = Date.now();
  const inputResult = AIAgentInputSchema.safeParse(rawInput);
  if (!inputResult.success) {
    return { success: false, data: null, error_code: 'VALIDATION_ERROR', error_message: `Invalid input: ${inputResult.error.message}` };
  }

  const input = inputResult.data;
  const guard = validateInput(input.text);
  if (guard.kind === "blocked") {
    return { success: false, data: null, error_code: 'GUARDRAIL_BLOCKED', error_message: guard.reason };
  }

  const pipeline = await runIntentPipeline({
    text: input.text, chat_id: input.chat_id,
    provider_id: input.provider_id, user_profile: input.user_profile,
  }, startMs);

  return { success: true, data: pipeline.result, error_message: null };
}

function detectSocial(text: string): { readonly intent: IntentType; readonly confidence: number } | null {
  const lower = text.toLowerCase().trim();

  const hasActionableKeywords =
    INTENT_KEYWORDS[INTENT.CANCEL_APPOINTMENT]?.keywords.some(k => lower.includes(k)) ||
    INTENT_KEYWORDS[INTENT.RESCHEDULE]?.keywords.some(k => lower.includes(k)) ||
    INTENT_KEYWORDS[INTENT.CHECK_AVAILABILITY]?.keywords.some(k => lower.includes(k)) ||
    INTENT_KEYWORDS[INTENT.CREATE_APPOINTMENT]?.keywords.some(k => lower.includes(k)) ||
    INTENT_KEYWORDS[INTENT.GET_MY_BOOKINGS]?.keywords.some(k => lower.includes(k)) ||
    INTENT_KEYWORDS[INTENT.ACTIVATE_REMINDERS]?.keywords.some(k => lower.includes(k)) ||
    INTENT_KEYWORDS[INTENT.DEACTIVATE_REMINDERS]?.keywords.some(k => lower.includes(k));

  if (hasActionableKeywords && text.length > 30) return null;

  if (GREETINGS.some(g => lower === g)) return { intent: INTENT.GREETING, confidence: 0.95 };
  if (GREETING_PHRASES.some(p => lower.includes(p))) return { intent: INTENT.GREETING, confidence: 0.9 };
  if (FAREWELLS.some(f => lower === f)) return { intent: INTENT.FAREWELL, confidence: 0.95 };
  if (FAREWELL_PHRASES.some(p => lower.includes(p))) return { intent: INTENT.FAREWELL, confidence: 0.9 };
  if (THANK_YOU_WORDS.some(t => lower.includes(t)) && text.length < 20) return { intent: INTENT.THANK_YOU, confidence: 0.95 };
  if (OFF_TOPIC_PATTERNS.some(p => lower.includes(p))) return { intent: INTENT.GENERAL_QUESTION, confidence: 0.85 };
  return null;
}

interface LLMInquiryResult {
  readonly intent: IntentType;
  readonly confidence: number;
  readonly provider: "groq" | "openai";
  readonly cot_reasoning: string;
}

async function runLLMInquiryWithPrompt(systemPrompt: string, userMsg: string): Promise<[Error | null, LLMInquiryResult | null]> {
  try {
    const response = await callLLM(systemPrompt, userMsg);

    const cleaned = sanitizeJSONResponse(response.content);
    const parsed = JSON.parse(cleaned) as Record<string, unknown>;

    const intent = parsed["intent"] as IntentType;
    const confidence = typeof parsed["confidence"] === "number" ? parsed["confidence"] : 0.5;

    return [null, {
      intent,
      confidence,
      provider: response.provider,
      cot_reasoning: "LLM with RAG context"
    }];
  } catch (e) {
    return [e instanceof Error ? e : new Error(String(e)), null];
  }
}

