});

interface RegionRow {
  readonly region_id: number;
  readonly name: string;
  readonly code: string;
  readonly country_code: string;
  readonly is_active: boolean;
  readonly sort_order: number;
}

const RegionDBRowSchema = z.tuple([
  z.number(), // region_id
  z.string(), // name
  z.string(), // code
  z.string(), // country_code
  z.boolean(), // is_active
  z.number(), // sort_order
]);

interface CommuneRow {
  readonly commune_id: number;
  readonly name: string;
  readonly region_id: number;
  readonly is_active: boolean;
  readonly region_name: string;
}

const CommuneDBRowSchema = z.tuple([
  z.number(), // commune_id
  z.string(), // name
  z.number(), // region_id
  z.boolean(), // is_active
  z.string(), // region_name
]);

export async function main(rawInput: unknown): Promise<[Error | null, unknown | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;
  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  try {
    switch (input.action) {
      case 'list_regions': {

        const rawRows = await sql.values`
          SELECT region_id, name, code, country_code, is_active, sort_order
          FROM regions WHERE is_active = true ORDER BY sort_order ASC, name ASC
        `;
        const parsedRows = z.array(RegionDBRowSchema).parse(rawRows);
        const regions: RegionRow[] = parsedRows.map((row) => ({
          region_id: row[0],
          name: row[1],
          code: row[2],
          country_code: row[3],
          is_active: row[4],
          sort_order: row[5],
        }));
        return [null, { regions, count: regions.length }];
      }

      case 'list_communes': {
        const regionId = input.region_id;

        let rawRows: unknown;
        if (regionId != null) {
          rawRows = await sql.values`
            SELECT c.commune_id, c.name, c.region_id, c.is_active, r.name AS region_name
            FROM communes c JOIN regions r ON r.region_id = c.region_id
            WHERE c.is_active = true AND c.region_id = ${regionId}
            ORDER BY c.name ASC
          `;
        } else {
          rawRows = await sql.values`
            SELECT c.commune_id, c.name, c.region_id, c.is_active, r.name AS region_name
            FROM communes c JOIN regions r ON r.region_id = c.region_id
            WHERE c.is_active = true ORDER BY r.sort_order ASC, c.name ASC
          `;
        }
        const parsedRows = z.array(CommuneDBRowSchema).parse(rawRows);
        const communes: CommuneRow[] = parsedRows.map((row) => ({
          commune_id: row[0],
          name: row[1],
          region_id: row[2],
          is_active: row[3],
          region_name: row[4],
        }));
        return [null, { communes, count: communes.length }];
      }

      case 'search_communes': {
        const search = input.search ?? '';
        const regionId = input.region_id;

        let rawRows: unknown;
        if (regionId != null) {
          rawRows = await sql.values`
            SELECT c.commune_id, c.name, c.region_id, c.is_active, r.name AS region_name
            FROM communes c JOIN regions r ON r.region_id = c.region_id
            WHERE c.is_active = true AND c.region_id = ${regionId}
              AND LOWER(c.name) LIKE LOWER(${`%${search}%`})
            ORDER BY c.name ASC LIMIT 50
          `;
        } else {
          rawRows = await sql.values`
            SELECT c.commune_id, c.name, c.region_id, c.is_active, r.name AS region_name
            FROM communes c JOIN regions r ON r.region_id = c.region_id
            WHERE c.is_active = true AND LOWER(c.name) LIKE LOWER(${`%${search}%`})
            ORDER BY r.sort_order ASC, c.name ASC LIMIT 50
          `;
        }
        const parsedRows = z.array(CommuneDBRowSchema).parse(rawRows);
        const communes: CommuneRow[] = parsedRows.map((row) => ({
          commune_id: row[0],
          name: row[1],
          region_id: row[2],
          is_active: row[3],
          region_name: row[4],
        }));
        return [null, { communes, count: communes.length }];
      }

      default: {
        const _exhaustive: never = input.action;
        return [new Error(`Unknown action: ${String(_exhaustive)}`), null];
      }
    }
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${msg}`), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// WEB ADMIN SPECIALTIES CRUD — Manage medical specialties
// ============================================================================
// Actions: list, create, update, delete, activate, deactivate
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import "@total-typescript/ts-reset";
import { z } from 'zod';
import postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

const TenantSchema = z.object({
  provider_id: z.uuid().optional(),
  user_id: z.uuid().optional(),
  admin_user_id: z.uuid().optional(),
  client_id: z.uuid().optional(),
  client_user_id: z.uuid().optional(),
}).partial();

const ActionSchema = z.enum(['list', 'create', 'update', 'delete', 'activate', 'deactivate']);

const InputSchema = z.object({
  action: ActionSchema,
  specialty_id: z.uuid().optional(),
  name: z.string().min(2).max(100).optional(),
  description: z.string().max(500).optional(),
  category: z.string().max(50).optional(),
  sort_order: z.number().int().min(0).max(999).optional(),
});

interface SpecialtyRow {
  readonly specialty_id: string;
  readonly name: string;
  readonly description: string | null;
  readonly category: string | null;
  readonly is_active: boolean;
  readonly sort_order: number;
  readonly created_at: string;
}

const SpecialtyRowSchema = z.object({
  specialty_id: z.uuid(),
  name: z.string(),
  description: z.string().nullable(),
  category: z.string().nullable(),
  is_active: z.boolean(),
  sort_order: z.number().int(),
  created_at: z.coerce.string(),
});

type Result<T> = [Error | null, T | null];

// ============================================================================
// DB OPERATIONS
// ============================================================================

async function listSpecialties(tx: postgres.Sql): Promise<Result<SpecialtyRow[]>> {
  try {

    const rawRows = await tx`SELECT specialty_id, name, description, category, is_active, sort_order, created_at FROM specialties ORDER BY sort_order ASC, name ASC`;
    const specialties = z.array(SpecialtyRowSchema).parse(rawRows);
    return [null, specialties];
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return [new Error(`list_failed: ${msg}`), null];
  }
}

async function createSpecialty(tx: postgres.Sql, input: Readonly<z.infer<typeof InputSchema>>): Promise<Result<SpecialtyRow>> {
  const name = input.name ?? '';
  if (name === '') return [new Error('create_failed: name is required'), null];


  const rawRows = await tx`INSERT INTO specialties (name, description, category, sort_order) VALUES (${name}, ${input.description ?? null}, ${input.category ?? 'Medicina'}, ${input.sort_order ?? 99}) RETURNING specialty_id, name, description, category, is_active, sort_order, created_at`;
  const parsedRows = z.array(SpecialtyRowSchema).parse(rawRows);
  if (parsedRows.length === 0 || parsedRows[0] === undefined) return [new Error('create_failed: no row returned'), null];

  return [null, parsedRows[0]];
}

async function updateSpecialty(tx: postgres.Sql, id: string, input: Readonly<z.infer<typeof InputSchema>>): Promise<Result<SpecialtyRow>> {
  const fields: string[] = [];
  const params: (string | number | null)[] = [];
  let pIdx = 1;
  if (input.name != null) { fields.push(`name = $${String(pIdx++)}`); params.push(input.name); }
  if (input.description != null) { fields.push(`description = $${String(pIdx++)}`); params.push(input.description); }
  if (input.category != null) { fields.push(`category = $${String(pIdx++)}`); params.push(input.category); }
  if (input.sort_order != null) { fields.push(`sort_order = $${String(pIdx++)}`); params.push(input.sort_order); }
  if (fields.length === 0) return [new Error('update_failed: no fields provided'), null];
  params.push(id);
  const query = `UPDATE specialties SET ${fields.join(', ')} WHERE specialty_id = $${String(pIdx)}::uuid RETURNING specialty_id, name, description, category, is_active, sort_order, created_at`;


  const rawRows = await tx.unsafe(query, params);
  const parsedRows = z.array(SpecialtyRowSchema).parse(rawRows);
  if (parsedRows.length === 0 || parsedRows[0] === undefined) return [new Error(`update_failed: specialty '${id}' not found`), null];

  return [null, parsedRows[0]];
}

async function deleteSpecialty(tx: postgres.Sql, id: string): Promise<Result<{ readonly deleted: boolean }>> {
  await tx`DELETE FROM specialties WHERE specialty_id = ${id}::uuid`;
  return [null, { deleted: true }];
}

// ============================================================================
// MAIN
// ============================================================================

export async function main(rawInput: unknown): Promise<[Error | null, unknown | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;
  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  const rawObj = typeof rawInput === 'object' && rawInput !== null ? (rawInput as Record<string, unknown>) : {};
  const tenantParsed = TenantSchema.safeParse(rawObj);
  let tenantId = '00000000-0000-0000-0000-000000000000';
  if (tenantParsed.success) {
    const data = tenantParsed.data;
    tenantId = data.provider_id ?? data.user_id ?? data.admin_user_id ?? data.client_id ?? data.client_user_id ?? tenantId;
  }

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      switch (input.action) {
        case 'list':
          return listSpecialties(tx);
        case 'create':
          return createSpecialty(tx, input);
        case 'update': {
          const id = input.specialty_id;
          if (id == null) return [new Error('update_failed: specialty_id is required'), null];
          return updateSpecialty(tx, id, input);
        }
        case 'delete': {
          const id = input.specialty_id;
          if (id == null) return [new Error('delete_failed: specialty_id is required'), null];
          return deleteSpecialty(tx, id);
        }
        case 'activate':
        case 'deactivate': {
          const id = input.specialty_id;
          if (id == null) return [new Error(`${input.action}_failed: specialty_id is required`), null];
          const active = input.action === 'activate';
          await tx`UPDATE specialties SET is_active = ${active} WHERE specialty_id = ${id}::uuid`;
          return [null, { specialty_id: id, is_active: active }];
        }
        default: {
          const _exhaustive: never = input.action;
          return [new Error(`Unknown action: ${String(_exhaustive)}`), null];
        }
      }
    });

    if (txErr !== null) return [txErr, null];
    if (txData === null) return [new Error('Operation failed'), null];
    return [null, txData];
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${msg}`), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// WEB BOOKING API — Web-compatible booking API (create, cancel, reschedule)
// ============================================================================
// Unified endpoint for web booking operations.
// Validates user permissions, checks availability, handles transactions.
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import { z } from 'zod';
import type postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import crypto from 'crypto';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  action: z.enum(['create', 'cancel', 'reschedule']),
  user_id: z.uuid(),
  booking_id: z.uuid().optional(),
  provider_id: z.uuid().optional(),
  service_id: z.uuid().optional(),
  start_time: z.string().optional(),
  end_time: z.string().optional(),
  cancellation_reason: z.string().max(500).optional(),
  idempotency_key: z.string().min(1).optional(),
});

interface BookingResult {
  readonly booking_id: string;
  readonly status: string;
  readonly message: string;
}

const UserRowSchema = z.object({
  user_id: z.string(),
  email: z.string().nullable(),
  client_id: z.string().nullable(),
});

const ClientIdRowSchema = z.object({
  client_id: z.string(),
});

const ServiceRowSchema = z.object({
  duration_minutes: z.number(),
});

const BookingRowSchema = z.object({
  booking_id: z.string(),
  status: z.string(),
  client_id: z.string(),
});

const BookingFullRowSchema = z.object({
  booking_id: z.string(),
  status: z.string(),
  client_id: z.string(),
  provider_id: z.string(),
  service_id: z.string(),
});

const InsertRowSchema = z.object({
  booking_id: z.string(),
  status: z.string(),
});

export async function main(rawInput: unknown): Promise<[Error | null, BookingResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const { action, user_id, booking_id, provider_id, service_id, start_time, cancellation_reason } = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (!dbUrl) {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is not set'), null];
  }

  const sql = createDbClient({ url: dbUrl });
  const tenantId = provider_id ?? user_id ?? '00000000-0000-0000-0000-000000000000';

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {

      const userRowsRaw = await tx`
        SELECT u.user_id, u.email, p.client_id
        FROM users u
        LEFT JOIN clients p ON p.client_id = u.user_id OR p.email = u.email
        WHERE u.user_id = ${user_id}::uuid
        LIMIT 1
      `;

      const parsedUser = z.array(UserRowSchema).safeParse(userRowsRaw);
      const userRow = parsedUser.success ? parsedUser.data[0] : undefined;
      if (!userRow) {
        return [new Error('User not found'), null];
      }

      let clientId = userRow.client_id;

      if (clientId === null && userRow.email !== null) {

        const clientRowsRaw = await tx`
          SELECT client_id FROM clients WHERE email = ${userRow.email} LIMIT 1
        `;
        const parsedClient = z.array(ClientIdRowSchema).safeParse(clientRowsRaw);
        if (parsedClient.success && parsedClient.data[0]) {
          clientId = parsedClient.data[0].client_id;
        }
      }

      if (clientId === null) {
        return [new Error('Client record not found. Please complete your profile first.'), null];
      }

      switch (action) {
        case 'create': {
          if (provider_id === undefined || service_id === undefined || start_time === undefined) {
            return [new Error('provider_id, service_id, and start_time are required for create'), null];
          }


          const serviceRowsRaw = await tx`
            SELECT duration_minutes FROM services WHERE service_id = ${service_id}::uuid LIMIT 1
          `;
          const parsedSvc = z.array(ServiceRowSchema).safeParse(serviceRowsRaw);
          const sRow = parsedSvc.success ? parsedSvc.data[0] : undefined;
          if (!sRow) {
            return [new Error('Service not found'), null];
          }

          const startTime = new Date(start_time);
          const endTime = new Date(startTime.getTime() + sRow.duration_minutes * 60000);

          const idempotencyKey = parsed.data.idempotency_key ?? crypto.randomUUID();


          const insertRowsRaw = await tx`
            INSERT INTO bookings (
              provider_id, client_id, service_id, start_time, end_time,
              status, idempotency_key, gcal_sync_status
            ) VALUES (
              ${provider_id}::uuid, ${clientId}::uuid, ${service_id}::uuid,
              ${start_time}, ${endTime.toISOString()},
              'pending', ${idempotencyKey}, 'pending'
            )
            RETURNING booking_id, status
          `;

          const parsedInsert = z.array(InsertRowSchema).safeParse(insertRowsRaw);
          const newRow = parsedInsert.success ? parsedInsert.data[0] : undefined;
          if (!newRow) {
            return [new Error('Failed to create booking. The slot may already be taken.'), null];
          }

          return [null, {
            booking_id: newRow.booking_id,
            status: newRow.status,
            message: 'Booking created successfully',
          }];
        }

        case 'cancel': {
          if (booking_id === undefined) {
            return [new Error('booking_id is required for cancel'), null];
          }


          const bookingRowsRaw = await tx`
            SELECT booking_id, status, client_id FROM bookings
            WHERE booking_id = ${booking_id}::uuid LIMIT 1
          `;

          const parsedBooking = z.array(BookingRowSchema).safeParse(bookingRowsRaw);
          const bRow = parsedBooking.success ? parsedBooking.data[0] : undefined;
          if (!bRow) {
            return [new Error('Booking not found'), null];
          }

          if (bRow.client_id !== clientId) {
            return [new Error('You can only cancel your own bookings'), null];
          }

          const status = bRow.status;
          if (status !== 'pending' && status !== 'confirmed') {
            return [new Error('Cannot cancel booking with status: ' + status), null];
          }


          const updateRowsRaw = await tx`
            UPDATE bookings SET
              status = 'cancelled',
              cancellation_reason = ${cancellation_reason ?? null},
              cancelled_by = 'client',
              updated_at = NOW()
            WHERE booking_id = ${booking_id}::uuid
            RETURNING booking_id, status
          `;

          const parsedUpdate = z.array(InsertRowSchema).safeParse(updateRowsRaw);
          const updatedRow = parsedUpdate.success ? parsedUpdate.data[0] : undefined;
          if (!updatedRow) {
            return [new Error('Failed to cancel booking'), null];
          }

          return [null, {
            booking_id: updatedRow.booking_id,
            status: updatedRow.status,
            message: 'Booking cancelled successfully',
          }];
        }

        case 'reschedule': {
          if (booking_id === undefined || start_time === undefined) {
            return [new Error('booking_id and start_time are required for reschedule'), null];
          }


          const bookingRowsRaw = await tx`
            SELECT booking_id, status, client_id, provider_id, service_id FROM bookings
            WHERE booking_id = ${booking_id}::uuid LIMIT 1
          `;

          const parsedBooking = z.array(BookingFullRowSchema).safeParse(bookingRowsRaw);
          const bRow = parsedBooking.success ? parsedBooking.data[0] : undefined;
          if (!bRow) {
            return [new Error('Booking not found'), null];
          }

          if (bRow.client_id !== clientId) {
            return [new Error('You can only reschedule your own bookings'), null];
          }

          const status = bRow.status;
          if (status !== 'pending' && status !== 'confirmed') {
            return [new Error('Cannot reschedule booking with status: ' + status), null];
          }


          const serviceRowsRaw = await tx`
            SELECT duration_minutes FROM services WHERE service_id = ${bRow.service_id}::uuid LIMIT 1
          `;
          const parsedSvc = z.array(ServiceRowSchema).safeParse(serviceRowsRaw);
          const sRow = parsedSvc.success ? parsedSvc.data[0] : undefined;
          if (!sRow) {
            return [new Error('Service not found'), null];
          }

          const startTimeDate = new Date(start_time);
          const endTime = new Date(startTimeDate.getTime() + sRow.duration_minutes * 60000);

          const idempotencyKey = parsed.data.idempotency_key ?? crypto.randomUUID();


          const insertRowsRaw = await tx`
            INSERT INTO bookings (
              provider_id, client_id, service_id, start_time, end_time,
              status, idempotency_key, rescheduled_from, gcal_sync_status
            ) VALUES (
              ${bRow.provider_id}::uuid, ${clientId}::uuid, ${bRow.service_id}::uuid,
              ${start_time}, ${endTime.toISOString()},
              'pending', ${idempotencyKey}, ${booking_id}::uuid, 'pending'
            )
            RETURNING booking_id, status
          `;

          const parsedInsert = z.array(InsertRowSchema).safeParse(insertRowsRaw);
          const newRow = parsedInsert.success ? parsedInsert.data[0] : undefined;
          if (!newRow) {
            return [new Error('Failed to create rescheduled booking. The slot may already be taken.'), null];
          }

          await tx`
            UPDATE bookings SET status = 'rescheduled', updated_at = NOW()
            WHERE booking_id = ${booking_id}::uuid
          `;

          return [null, {
            booking_id: newRow.booking_id,
            status: newRow.status,
            message: 'Booking rescheduled successfully',
          }];
        }

        default: {
          const _exhaustive: never = action;
          return [new Error(`Unknown action: ${String(_exhaustive)}`), null];
        }
      }
    });

    if (txErr !== null) {
      const message = txErr.message;
      if (message.includes('duplicate key') || message.includes('unique constraint') || message.includes('conflicting key value violates exclusion constraint')) {
        return [new Error('The selected time slot is already booked. Please choose another time.'), null];
      }
      if (message.startsWith('transaction_failed: ')) {
        return [new Error(message.slice(20)), null];
      }
      return [txErr, null];
    }

    return [null, txData];

  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    if (message.includes('duplicate key') || message.includes('unique constraint') || message.includes('conflicting key value violates exclusion constraint')) {
      return [new Error('The selected time slot is already booked. Please choose another time.'), null];
    }
    // Check if the original txErr had a message without the wrapping 'transaction_failed:' 
    if (message.startsWith('transaction_failed: ')) {
      const realMsg = message.slice(20);
      if (realMsg.includes('duplicate key') || realMsg.includes('unique constraint') || realMsg.includes('conflicting key value violates exclusion constraint')) {
        return [new Error('The selected time slot is already booked. Please choose another time.'), null];
      }
      return [new Error(realMsg), null];
    }
    return [new Error('Internal error: ' + message), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// WEB PATIENT BOOKINGS — Client booking history and upcoming appointments
// ============================================================================
// Returns upcoming and past bookings for a client.
// Supports filtering by status and date range.
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  client_user_id: z.uuid(),
  status: z.enum(['all', 'pending', 'confirmed', 'in_service', 'completed', 'cancelled', 'no_show', 'rescheduled']).default('all'),
  limit: z.number().int().min(1).max(100).default(50),
  offset: z.number().int().min(0).default(0),
});

interface BookingInfo {
  readonly booking_id: string;
  readonly provider_name: string;
  readonly provider_specialty: string;
  readonly service_name: string;
  readonly start_time: string;
  readonly end_time: string;
  readonly status: string;
  readonly cancellation_reason: string | null;
  readonly can_cancel: boolean;
  readonly can_reschedule: boolean;
}

interface BookingsResult {
  readonly upcoming: readonly BookingInfo[];
  readonly past: readonly BookingInfo[];
  readonly total: number;
}

export async function main(rawInput: unknown): Promise<[Error | null, BookingsResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is not set'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  const rawObj = typeof rawInput === 'object' && rawInput !== null ? rawInput : {};
  let tenantId = '00000000-0000-0000-0000-000000000000';
  const tenantKeys = ['provider_id', 'user_id', 'admin_user_id', 'client_id', 'client_user_id'] as const;
  for (const key of tenantKeys) {
    const val = (rawObj as Record<string, unknown>)[key];
    if (typeof val === 'string') {
      tenantId = val;
      break;
    }
  }

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      const userRows = await tx.values<[string][]>`
        SELECT p.client_id FROM clients p
        INNER JOIN users u ON u.user_id = p.client_id
        WHERE u.user_id = ${input.client_user_id}::uuid
        LIMIT 1
      `;

      let clientId: string;

      if (userRows[0] === undefined) {
        const clientRows = await tx.values<[string][]>`
          SELECT client_id FROM clients
          WHERE email = (SELECT email FROM users WHERE user_id = ${input.client_user_id}::uuid LIMIT 1)
          LIMIT 1
        `;
        const pRow = clientRows[0];
        if (pRow === undefined) {
          return [new Error('Client record not found for this user'), null];
        }
        clientId = pRow[0];
      } else {
        clientId = userRows[0][0];
      }

      const cancellableStatuses = ['pending', 'confirmed'];
      const reschedulableStatuses = ['pending', 'confirmed'];
      const now = new Date().toISOString();

      let statusCondition = '';
      const statusParams: (string | number)[] = [clientId];
      let paramIdx = 2;

      if (input.status !== 'all') {
        statusCondition = ' AND b.status = $' + String(paramIdx);
        statusParams.push(input.status);
        paramIdx++;
      }

      const rows = await tx.values<[string, string, string, string, string, string | null, string, string, string][]>`
        SELECT b.booking_id, b.start_time, b.end_time, b.status,
               b.cancellation_reason,
               p.name AS provider_name, p.specialty AS provider_specialty,
               s.name AS service_name, b.start_time
        FROM bookings b
        INNER JOIN providers p ON b.provider_id = p.provider_id
        INNER JOIN services s ON b.service_id = s.service_id
        WHERE b.client_id = ${clientId}::uuid
        ${statusCondition}
        ORDER BY b.start_time DESC
        LIMIT ${input.limit} OFFSET ${input.offset}
      `;

      const bookings: BookingInfo[] = rows.map((row) => ({
        booking_id: row[0],
        start_time: row[1],
        end_time: row[2],
        status: row[3],
        cancellation_reason: row[4],
        provider_name: row[5],
        provider_specialty: row[6],
        service_name: row[7],
        can_cancel: cancellableStatuses.includes(row[3]),
        can_reschedule: reschedulableStatuses.includes(row[3]),
      }));

      const upcoming = bookings.filter((b) => b.start_time > now);
      const past = bookings.filter((b) => b.start_time <= now);

      const countRows = await tx.values<[bigint | number][]>`
        SELECT COUNT(*) FROM bookings
        WHERE client_id = ${clientId}::uuid
        ${statusCondition}
      `;
      const total = countRows[0] !== undefined ? Number(countRows[0][0]) : 0;

      return [null, { upcoming, past, total }];
    });

    if (txErr !== null) return [txErr, null];
    if (txData === null) return [new Error('Bookings query failed'), null];
    return [null, txData];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return [new Error('Internal error: ' + message), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// WEB PROVIDER NOTES — Clinical notes CRUD with AES-256-GCM encryption
// ============================================================================
// Notes are encrypted at rest so only the owning provider can read them.
// Admins cannot decrypt note content even with direct DB access.
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import { encryptData, decryptData } from '../internal/crypto';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

const InputSchema = z.object({
  provider_id: z.uuid(),
  action: z.enum(['create', 'read', 'update', 'delete', 'list']),
  note_id: z.uuid().optional(),
  booking_id: z.uuid().optional(),
  client_id: z.uuid().optional(),
  content: z.string().min(1).max(5000).optional(),
  tag_ids: z.array(z.uuid()).optional().default([]),
});

interface NoteRow {
  readonly note_id: string;
  readonly booking_id: string;
  readonly client_id: string;
  readonly provider_id: string;
  readonly content_encrypted: string | null;
  readonly content: string;
  readonly encryption_version: number;
  readonly created_at: string;
  readonly updated_at: string;
  tags: readonly { readonly tag_id: string; readonly name: string; readonly color: string }[];
}

type Result<T> = [Error | null, T | null];

const TagRowSchema = z.object({
  tag_id: z.string(),
  name: z.string(),
  color: z.string(),
});

const NoteFullRowSchema = z.object({
  note_id: z.string(),
  booking_id: z.string(),
  client_id: z.string(),
  provider_id: z.string(),
  content_encrypted: z.string().nullable(),
  encryption_version: z.coerce.number(),
  created_at: z.coerce.string(),
  updated_at: z.coerce.string(),
});

const ListNoteRowSchema = z.object({
  note_id: z.string(),
  booking_id: z.string(),
  client_id: z.string(),
  provider_id: z.string(),
  content_encrypted: z.string().nullable(),
  encryption_version: z.coerce.number(),
  created_at: z.coerce.string(),
  updated_at: z.coerce.string(),
  tag_id: z.string().nullable(),
  name: z.string().nullable(),
  color: z.string().nullable(),
});

// ============================================================================
// TAG HELPERS
// ============================================================================

async function assignTags(tx: postgres.Sql, noteId: string, tagIds: readonly string[]): Promise<Result<true>> {
  for (const tagId of tagIds) {
    await tx`
      INSERT INTO note_tags (note_id, tag_id)
      VALUES (${noteId}::uuid, ${tagId}::uuid)
      ON CONFLICT (note_id, tag_id) DO NOTHING
    `;
  }
  return [null, true];
}

async function getNoteTags(tx: postgres.Sql, noteId: string): Promise<Result<{ tag_id: string; name: string; color: string }[]>> {

  const rowsRaw = await tx`
    SELECT t.tag_id, t.name, t.color
    FROM note_tags nt
    JOIN tags t ON t.tag_id = nt.tag_id
    WHERE nt.note_id = ${noteId}::uuid
    ORDER BY t.name ASC
  `;
  const parsed = z.array(TagRowSchema).safeParse(rowsRaw);
  if (!parsed.success) return [new Error(`failed_to_get_tags: ${parsed.error.message}`), null];
  return [null, parsed.data];
}

// ============================================================================
// ENCRYPT content before storing
// ============================================================================

function encryptContent(plainContent: string): { readonly encrypted: string; readonly version: number } {
  const encrypted = encryptData(plainContent);
  return { encrypted, version: 1 };
}

// ============================================================================
// DECRYPT content after reading
// ============================================================================

function decryptContent(encrypted: string | null): string {
  if (encrypted == null) return '';
  try {
    return decryptData(encrypted);
  } catch {
    return '[ERROR: Unable to decrypt note]';
  }
}

// ============================================================================
// CREATE note (encrypted)
// ============================================================================

async function createNote(
  tx: postgres.Sql,
  providerId: string,
  bookingId: string,
  clientId: string,
  content: string,
  tagIds: readonly string[],
): Promise<Result<NoteRow>> {
  const { encrypted, version } = encryptContent(content);


  const rowsRaw = await tx`
    INSERT INTO service_notes (provider_id, booking_id, client_id, content_encrypted, encryption_version)
    VALUES (${providerId}::uuid, ${bookingId}::uuid, ${clientId}::uuid, ${encrypted}, ${version})
    RETURNING note_id, booking_id, client_id, provider_id, content_encrypted, encryption_version, created_at, updated_at
  `;
  const parsed = z.array(NoteFullRowSchema).safeParse(rowsRaw);
  const row = parsed.success ? parsed.data[0] : undefined;

  if (row === undefined) return [new Error('create_failed: no row returned'), null];

  // Assign tags
  if (tagIds.length > 0) {
    await assignTags(tx, row.note_id, tagIds);
  }

  // Get tags for response
  const [, tags] = await getNoteTags(tx, row.note_id);

  return [null, {
    ...row,
    content: content,
    tags: tags ?? [],
  }];
}

// ============================================================================
// READ note (decrypt content)
// ============================================================================

async function readNote(tx: postgres.Sql, providerId: string, noteId: string): Promise<Result<NoteRow>> {

  const rowsRaw = await tx`
    SELECT note_id, booking_id, client_id, provider_id, content_encrypted, encryption_version, created_at, updated_at
    FROM service_notes
    WHERE note_id = ${noteId}::uuid AND provider_id = ${providerId}::uuid
    LIMIT 1
  `;
  const parsed = z.array(NoteFullRowSchema).safeParse(rowsRaw);
  const row = parsed.success ? parsed.data[0] : undefined;

  if (row === undefined) return [new Error('Note not found or access denied'), null];

  const [, tags] = await getNoteTags(tx, row.note_id);

  return [null, {
    ...row,
    content: decryptContent(row.content_encrypted),
    tags: tags ?? [],
  }];
}

// ============================================================================
// UPDATE note (re-encrypt)
// ============================================================================

async function updateNote(
  tx: postgres.Sql,
  providerId: string,
  noteId: string,
  content: string,
  tagIds: readonly string[],
): Promise<Result<NoteRow>> {
  const { encrypted, version } = encryptContent(content);


  const rowsRaw = await tx`
    UPDATE service_notes
    SET content_encrypted = ${encrypted}, encryption_version = ${version}, updated_at = NOW()
    WHERE note_id = ${noteId}::uuid AND provider_id = ${providerId}::uuid
    RETURNING note_id, booking_id, client_id, provider_id, content_encrypted, encryption_version, created_at, updated_at
  `;
  const parsed = z.array(NoteFullRowSchema).safeParse(rowsRaw);
  const row = parsed.success ? parsed.data[0] : undefined;

  if (row === undefined) return [new Error('Note not found or access denied'), null];

  // Replace tags
  await tx`DELETE FROM note_tags WHERE note_id = ${noteId}::uuid`;
  if (tagIds.length > 0) {
    await assignTags(tx, noteId, tagIds);
  }

  const [, tags] = await getNoteTags(tx, noteId);

  return [null, {
    ...row,
    content: content,
    tags: tags ?? [],
  }];
}

// ============================================================================
// DELETE note
// ============================================================================

async function deleteNote(tx: postgres.Sql, providerId: string, noteId: string): Promise<Result<{ readonly deleted: boolean }>> {
  await tx`DELETE FROM service_notes WHERE note_id = ${noteId}::uuid AND provider_id = ${providerId}::uuid`;
  return [null, { deleted: true }];
}

// ============================================================================
// LIST notes for a booking (decrypt all)
// ============================================================================

async function listNotes(
  tx: postgres.Sql,
  providerId: string,
  bookingId?: string
): Promise<Result<NoteRow[]>> {

  let rowsRaw: unknown;
  if (bookingId != null) {
    rowsRaw = await tx`
      SELECT sn.note_id, sn.booking_id, sn.client_id, sn.provider_id, sn.content_encrypted,
             sn.encryption_version, sn.created_at, sn.updated_at,
             t.tag_id, t.name, t.color
      FROM service_notes sn
      LEFT JOIN note_tags nt ON nt.note_id = sn.note_id
      LEFT JOIN tags t ON t.tag_id = nt.tag_id
      WHERE sn.provider_id = ${providerId}::uuid
        AND sn.booking_id = ${bookingId}::uuid
      ORDER BY sn.created_at DESC, t.name ASC
    `;
  } else {
    rowsRaw = await tx`
      SELECT sn.note_id, sn.booking_id, sn.client_id, sn.provider_id, sn.content_encrypted,
             sn.encryption_version, sn.created_at, sn.updated_at,
             t.tag_id, t.name, t.color
      FROM service_notes sn
      LEFT JOIN note_tags nt ON nt.note_id = sn.note_id
      LEFT JOIN tags t ON t.tag_id = nt.tag_id
      WHERE sn.provider_id = ${providerId}::uuid
      ORDER BY sn.created_at DESC, t.name ASC
      LIMIT 100
    `;
  }

  const parsed = z.array(ListNoteRowSchema).safeParse(rowsRaw);
  if (!parsed.success) return [new Error(`failed_to_list_notes: ${parsed.error.message}`), null];

  // Group by note_id
  const noteMap = new Map<string, NoteRow>();
  for (const row of parsed.data) {
    const noteId = row.note_id;
    if (!noteMap.has(noteId)) {
      noteMap.set(noteId, {
        note_id: row.note_id,
        booking_id: row.booking_id,
        client_id: row.client_id,
        provider_id: row.provider_id,
        content_encrypted: row.content_encrypted,
        encryption_version: row.encryption_version,
        created_at: row.created_at,
        updated_at: row.updated_at,
        content: decryptContent(row.content_encrypted),
        tags: [],
      });
    }
    const note = noteMap.get(noteId);
    if (note != null && row.tag_id !== null && row.name !== null && row.color !== null) {
      note.tags = [...note.tags, { tag_id: row.tag_id, name: row.name, color: row.color }];
    }
  }

  return [null, Array.from(noteMap.values())];
}

// ============================================================================
// MAIN
// ============================================================================

export async function main(rawInput: unknown): Promise<[Error | null, unknown | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;
  const dbUrl = process.env['DATABASE_URL'];
  if (!dbUrl) {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  const tenantId = input.provider_id;

  try {
    const [txErr, txResult] = await withTenantContext<unknown>(sql, tenantId, async (tx) => {
      switch (input.action) {
        case 'create': {
          const bookingId = input.booking_id;
          const clientId = input.client_id;
          const content = input.content;
          if (bookingId == null || clientId == null || content == null) {
            return [new Error('create requires booking_id, client_id, and content'), null];
          }
          return createNote(tx, input.provider_id, bookingId, clientId, content, input.tag_ids);
        }

        case 'read': {
          const noteId = input.note_id;
          if (noteId == null) return [new Error('read requires note_id'), null];
          return readNote(tx, input.provider_id, noteId);
        }

        case 'update': {
          const noteId = input.note_id;
          const content = input.content;
          if (noteId == null || content == null) return [new Error('update requires note_id and content'), null];
          return updateNote(tx, input.provider_id, noteId, content, input.tag_ids);
        }

        case 'delete': {
          const noteId = input.note_id;
          if (noteId == null) return [new Error('delete requires note_id'), null];
          return deleteNote(tx, input.provider_id, noteId);
        }

        case 'list': {
          const [err, result] = await listNotes(tx, input.provider_id, input.booking_id);
          if (err != null) return [err, null];
          const notes = result ?? [];
          return [null, { notes, count: notes.length }];
        }

        default: {
          const _exhaustive: never = input.action;
          return [new Error(`Unknown action: ${String(_exhaustive)}`), null];
        }
      }
    });

    if (txErr !== null) return [txErr, null];
    if (txResult === null) return [new Error('Operation failed'), null];
    return [null, txResult];
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${msg}`), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// WEB PROVIDER PROFILE — Provider self-service profile management
// ============================================================================
// Actions: get_profile, update_profile, change_password
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import "@total-typescript/ts-reset";
import { z } from 'zod';
import postgres from 'postgres';
import { hashPassword, verifyPassword, validatePasswordPolicy } from '../internal/crypto';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

const ActionSchema = z.enum(['get_profile', 'update_profile', 'change_password']);

const InputSchema = z.object({
  action: ActionSchema,
  provider_id: z.uuid(),
  name: z.string().min(2).max(200).optional(),
  email: z.email().optional(),
  phone_app: z.string().max(20).optional(),
  phone_contact: z.string().max(20).optional(),
  telegram_chat_id: z.string().max(100).optional(),
  gcal_calendar_id: z.string().max(500).optional(),
  address_street: z.string().max(300).optional(),
  address_number: z.string().max(20).optional(),
  address_complement: z.string().max(200).optional(),
  address_sector: z.string().max(200).optional(),
  region_id: z.number().int().optional(),
  commune_id: z.number().int().optional(),
  current_password: z.string().optional(),
  new_password: z.string().optional(),
});

type Result<T> = [Error | null, T | null];

interface ProfileRow {
  readonly id: string;
  readonly name: string;
  readonly email: string;
  readonly honorific_label: string | null;
  readonly specialty_name: string | null;
  readonly timezone_name: string | null;
  readonly phone_app: string | null;
  readonly phone_contact: string | null;
  readonly telegram_chat_id: string | null;
  readonly gcal_calendar_id: string | null;
  readonly address_street: string | null;
  readonly address_number: string | null;
  readonly address_complement: string | null;
  readonly address_sector: string | null;
  readonly region_name: string | null;
  readonly commune_name: string | null;
  readonly is_active: boolean;
  readonly has_password: boolean;
  readonly last_password_change: string | null;
}

const ProfileDBRowSchema = z.tuple([
  z.string(), // id
  z.string(), // name
  z.string(), // email
  z.string().nullable(), // honorific_label
  z.string().nullable(), // specialty_name
  z.string().nullable(), // timezone_name
  z.string().nullable(), // phone_app
  z.string().nullable(), // phone_contact
  z.string().nullable(), // telegram_chat_id
  z.string().nullable(), // gcal_calendar_id
  z.string().nullable(), // address_street
  z.string().nullable(), // address_number
  z.string().nullable(), // address_complement
  z.string().nullable(), // address_sector
  z.string().nullable(), // region_name
  z.string().nullable(), // commune_name
  z.boolean(), // is_active
  z.boolean(), // has_password
  z.string().nullable(), // last_password_change
]);

async function getProfile(sql: postgres.Sql  , providerId: string): Promise<Result<ProfileRow>> {

  const rowsRaw = await sql.values`
    SELECT
      p.provider_id, p.name, p.email, h.label AS honorific_label,
      s.name AS specialty_name, t.name AS timezone_name,
      p.phone_app, p.phone_contact, p.telegram_chat_id, p.gcal_calendar_id,
      p.address_street, p.address_number, p.address_complement, p.address_sector,
      r.name AS region_name, c.name AS commune_name,
      p.is_active, (p.password_hash IS NOT NULL) AS has_password,
      p.last_password_change
    FROM providers p
    LEFT JOIN honorifics h ON h.honorific_id = p.honorific_id
    LEFT JOIN specialties s ON s.specialty_id = p.specialty_id
    LEFT JOIN timezones t ON t.id = p.timezone_id
    LEFT JOIN regions r ON r.region_id = p.region_id
    LEFT JOIN communes c ON c.commune_id = p.commune_id
    WHERE p.provider_id = ${providerId}::uuid
    LIMIT 1
  `;
  const parsed = z.array(ProfileDBRowSchema).safeParse(rowsRaw);
  const row = parsed.success ? parsed.data[0] : undefined;
  if (row === undefined) return [new Error('Provider not found'), null];
  return [null, {
    id: row[0],
    name: row[1],
    email: row[2],
    honorific_label: row[3],
    specialty_name: row[4],
    timezone_name: row[5],
    phone_app: row[6],
    phone_contact: row[7],
    telegram_chat_id: row[8],
    gcal_calendar_id: row[9],
    address_street: row[10],
    address_number: row[11],
    address_complement: row[12],
    address_sector: row[13],
    region_name: row[14],
    commune_name: row[15],
    is_active: row[16],
    has_password: row[17],
    last_password_change: row[18],
  }];
}

async function updateProfile(sql: postgres.Sql  , providerId: string, input: Readonly<z.infer<typeof InputSchema>>): Promise<Result<ProfileRow>> {
  const fields: string[] = [];
  const params: (string | number | null)[] = [];
  let pIdx = 1;
  if (input.name != null) { fields.push(`name = $${String(pIdx++)}`); params.push(input.name); }
  if (input.email != null) { fields.push(`email = $${String(pIdx++)}`); params.push(input.email); }
  if (input.phone_app != null) { fields.push(`phone_app = $${String(pIdx++)}`); params.push(input.phone_app); }
  if (input.phone_contact != null) { fields.push(`phone_contact = $${String(pIdx++)}`); params.push(input.phone_contact); }
  if (input.telegram_chat_id != null) { fields.push(`telegram_chat_id = $${String(pIdx++)}`); params.push(input.telegram_chat_id); }
  if (input.gcal_calendar_id != null) { fields.push(`gcal_calendar_id = $${String(pIdx++)}`); params.push(input.gcal_calendar_id); }
  if (input.address_street != null) { fields.push(`address_street = $${String(pIdx++)}`); params.push(input.address_street); }
  if (input.address_number != null) { fields.push(`address_number = $${String(pIdx++)}`); params.push(input.address_number); }
  if (input.address_complement != null) { fields.push(`address_complement = $${String(pIdx++)}`); params.push(input.address_complement); }
  if (input.address_sector != null) { fields.push(`address_sector = $${String(pIdx++)}`); params.push(input.address_sector); }
  if (input.region_id != null) { fields.push(`region_id = $${String(pIdx++)}`); params.push(input.region_id); }
  if (input.commune_id != null) { fields.push(`commune_id = $${String(pIdx++)}`); params.push(input.commune_id); }

  if (fields.length === 0) return [new Error('update_profile_failed: no fields provided'), null];
  fields.push(`updated_at = NOW()`);
  params.push(providerId);

  const query = `UPDATE providers SET ${fields.join(', ')} WHERE provider_id = $${String(pIdx)}::uuid`;
  await sql.unsafe(query, params);

  return getProfile(sql, providerId);
}

const PasswordHashSchema = z.tuple([z.string().nullable()]);

async function changePassword(
  sql: postgres.Sql  ,
  providerId: string,
  currentPassword: string,
  newPassword: string
): Promise<Result<{ readonly success: boolean; readonly message: string }>> {
  const policy = validatePasswordPolicy(newPassword);
  if (!policy.valid) return [new Error(`Password policy failed: ${policy.errors.join(', ')}`), null];


  const providersRaw = await sql.values`SELECT password_hash FROM providers WHERE provider_id = ${providerId}::uuid LIMIT 1`;
  const parsed = z.array(PasswordHashSchema).safeParse(providersRaw);
  const provider = parsed.success ? parsed.data[0] : undefined;

  if (provider === undefined) return [new Error('Provider not found'), null];
  if (provider[0] === null) return [new Error('No password set. Contact admin.'), null];

  const isValid = await verifyPassword(currentPassword, provider[0]);
  if (!isValid) return [new Error('Current password is incorrect'), null];

  const newHash = await hashPassword(newPassword);
  await sql`
    UPDATE providers SET password_hash = ${newHash}, last_password_change = NOW(), updated_at = NOW()
    WHERE provider_id = ${providerId}::uuid
  `;

  return [null, { success: true, message: 'Password changed successfully' }];
}

export async function main(rawInput: unknown): Promise<[Error | null, unknown | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;
  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });
  const tenantId = input.provider_id;

  try {
    switch (input.action) {
      case 'get_profile': {
        const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
          return getProfile(tx, input.provider_id);
        });
        if (txErr != null) return [txErr, null];
        if (txData === null) return [new Error('Provider not found'), null];
        return [null, txData];
      }

      case 'update_profile': {
        const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
          return updateProfile(tx, input.provider_id, input);
        });
        if (txErr != null) return [txErr, null];
        if (txData === null) return [new Error('Update failed'), null];
        return [null, txData];
      }

      case 'change_password': {
        const currentPw = input.current_password;
        const newPw = input.new_password;
        if (currentPw == null || newPw == null) return [new Error('change_password requires current_password and new_password'), null];
        const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
          return changePassword(tx, input.provider_id, currentPw, newPw);
        });
        if (txErr != null) return [txErr, null];
        if (txData === null) return [new Error('Password change failed'), null];
        return [null, txData];
      }

      default: {
        const _exhaustive: never = input.action;
        return [new Error(`Unknown action: ${String(_exhaustive)}`), null];
      }
    }
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${msg}`), null];
  } finally {
    await sql.end();
  }
}
